// Unit 19: Ausländerbehörde
// Level: B1

const UNIT_19 =
{n:19,lang:"de",srcLang:"en",track:"v2",title:"Ausländerbehörde",sub:"Immigration office, passive with modals, advanced subordination, residence permit",icon:"\uD83D\uDCCB",level:"B1.2",color:"#7B5EE8",lessons:[

// ===== LESSON 1: "Wartenummer B089" (Queue Number B089) =====
// Story intro + vocabulary. 16 new words. 22 steps.
{id:"deu_r19l1",title:"Wartenummer B089",icon:"\uD83C\uDFE2",xp:15,board:true,steps:[
{type:"intro",title:"Wartenummer B089",desc:"Verumius sits in the immigration office. Queue number B089. The display shows A247. His folder is perfectly organized. Hildi helped.",goals:["Learn key vocabulary for government offices and applications","Understand how a German Amt works","Follow Verumius in the waiting room of the Ausländerbehörde"]},


{type:"teach",trg:"die Behörde",src:"the government authority",pos:"noun",gender:"f",note:"From 'beherrschen' (to govern). Any official authority.\nAusländerbehörde = foreigners' authority.",example:"A: Welche Behörde ist für Visa zuständig?\nB: Die Ausländerbehörde.\nA: Und wo finde ich die?\nB: Am Friedrichring 12, dritter Stock.",exampleSrc:"A: Which authority handles visas?\nB: The immigration office.\nA: And where can I find it?\nB: At Friedrichring 12, third floor.",funFact:"Germans have a Behörde for everything. The word comes from 'beherrschen' (to govern). There are over 14,000 different Behörden in Germany, from the Finanzamt to the Jugendamt."},

{type:"teach",trg:"das Amt",src:"the office, the bureau",pos:"noun",gender:"n",note:"From Gothic 'andbahti' (service). Plural: Ämter.\nBürgeramt, Finanzamt, Standesamt.",example:"A: Ich muss zum Amt gehen.\nB: Zu welchem Amt?\nA: Zum Bürgeramt, für die Anmeldung.\nB: Hast du einen Termin?",exampleSrc:"A: I have to go to the office.\nB: Which office?\nA: The citizens' office, for registration.\nB: Do you have an appointment?",funFact:"The word Amt comes from Gothic 'andbahti' (service). An Amt is an office or bureau. Bürgeramt, Finanzamt, Standesamt. German bureaucracy runs on Ämter. Das Amt is neuter, like most institutions."},

{type:"teach",trg:"das Dokument",src:"the document",pos:"noun",gender:"n",note:"From Latin 'documentum' (lesson/proof). Plural: Dokumente.\nNearly identical in English.",example:"A: Haben Sie alle Dokumente dabei?\nB: Ja, hier ist mein Ordner.\nA: Sehr gut. Ich prüfe alles der Reihe nach.\nB: Bitte, nehmen Sie sich Zeit.",exampleSrc:"A: Do you have all documents with you?\nB: Yes, here is my folder.\nA: Very good. I'll check everything in order.\nB: Please, take your time.",funFact:"In Germany, you need Dokumente for everything: renting an apartment, opening a bank account, starting a job, even getting a library card. The phrase 'Bringen Sie alle Dokumente mit' is survival German."},

{type:"teach",trg:"der Antrag",src:"the application, the formal request",pos:"noun",gender:"m",note:"An- (toward) + tragen (to carry). Literally 'to carry toward.'\n'Einen Antrag stellen' = to file an application.",example:"A: Ich möchte einen Antrag stellen.\nB: Welchen Antrag?\nA: Einen Antrag auf Aufenthaltstitel.\nB: Füllen Sie bitte dieses Formular aus.",exampleSrc:"A: I would like to file an application.\nB: Which application?\nA: An application for a residence permit.\nB: Please fill out this form.",funFact:"'Einen Antrag stellen' (to file an application) is survival vocabulary in Germany. The verb is stellen, not machen. Every official process begins with an Antrag."},

{type:"mc",q:"Was ist ein Amt?",opts:["Eine offizielle Behörde oder Verwaltungsstelle","Ein Geschäft oder eine Bäckerei","Ein Restaurant oder eine Gaststätte","Ein Krankenhaus oder eine Arztpraxis"],ans:"Eine offizielle Behörde oder Verwaltungsstelle",hint:"Think B\u00fcrgeramt, Finanzamt, Standesamt. All are types of this."},

{type:"teach",trg:"das Visum",src:"the visa",pos:"noun",gender:"n",note:"From Latin 'visum' (something seen/approved). Plural: Visa.\nDer Aufenthaltstitel replaces it long-term.",example:"A: Wie lange ist Ihr Visum gültig?\nB: Noch drei Monate.\nA: Dann müssen Sie rechtzeitig verlängern.\nB: Ja, deshalb bin ich heute hier.",exampleSrc:"A: How long is your visa valid?\nB: Three more months.\nA: Then you must renew in time.\nB: Yes, that's why I'm here today.",funFact:"Every non-EU resident in Germany needs a Visum. The Aufenthaltstitel (residence permit) replaces it long-term. Das Visum, plural: Visa. The word comes from Latin 'visum' (something officially seen and approved)."},

{type:"teach",trg:"der Aufenthalt",src:"the stay, the residence",pos:"noun",gender:"m",note:"COMPOUND: Auf (on/at) + Enthalt (holding/staying).\nAuf- (up/upon) + enthalten (to hold). A stay or residence.\nAufenthaltserlaubnis = residence permit.",example:"A: Wie lange dauert Ihr Aufenthalt in Deutschland?\nB: Ich lebe seit einem Jahr hier.\nA: Und Sie möchten den Aufenthalt verlängern?\nB: Ja, unbefristet, wenn möglich.",exampleSrc:"A: How long is your stay in Germany?\nB: I've lived here for a year.\nA: And you want to extend the stay?\nB: Yes, indefinitely, if possible.",funFact:"Aufenthaltserlaubnis, Aufenthaltstitel, Aufenthaltsgenehmigung. German compound words build meaning layer by layer. Aufenthalt (stay) is the root of an entire family of immigration terms."},

{type:"teach",trg:"die Unterlage",src:"the document, the paperwork",pos:"noun",gender:"f",note:"Unter (under) + Lage (position). Usually plural: Unterlagen.\n'Haben Sie alle Unterlagen?' is the classic question.",example:"A: Haben Sie alle Unterlagen?\nB: Ja, alles ist in diesem Ordner.\nA: Geburtsurkunde, Meldebescheinigung?\nB: Alles dabei, in der richtigen Reihenfolge.",exampleSrc:"A: Do you have all the paperwork?\nB: Yes, everything is in this folder.\nA: Birth certificate, registration confirmation?\nB: Everything's here, in the right order.",funFact:"Die Unterlagen (plural) means 'documents/paperwork.' Every Behörde asks: 'Haben Sie alle Unterlagen?' The word literally means 'things lying underneath,' supporting your case."},

{type:"teach",trg:"die Frist",src:"the deadline",pos:"noun",gender:"f",note:"From Old High German 'frist' (time period).\n'Die Frist läuft ab' = the deadline expires.",example:"A: Wann ist die Frist für den Antrag?\nB: Am 15. März.\nA: Dann habe ich noch zwei Wochen.\nB: Reichen Sie alles rechtzeitig ein.",exampleSrc:"A: When is the deadline for the application?\nB: March 15th.\nA: Then I have two more weeks.\nB: Submit everything on time.",funFact:"Missing a Frist in German bureaucracy has real consequences. Always ask: 'Wann ist die Frist?' The word comes from Old High German 'frist' (time period). Once the Frist expires, your case may be closed."},

{type:"mc",q:"Welches Wort beschreibt eine offizielle Stelle, die für Verwaltung zuständig ist?",opts:["der Antrag","die Behörde","das Visum","die Frist"],ans:"die Behörde",hint:"This word refers to any government authority or office."},

{type:"teach",trg:"nötig",src:"necessary, needed",pos:"adj",gender:null,note:"From 'Not' (need/necessity). Stronger than 'brauchen.'\n'Es ist nötig, alle Dokumente mitzubringen.'",example:"A: Ist ein Passfoto nötig?\nB: Ja, zwei Passfotos sind nötig.\nA: Biometrisch?\nB: Ja, das ist Vorschrift.",exampleSrc:"A: Is a passport photo necessary?\nB: Yes, two passport photos are necessary.\nA: Biometric?\nB: Yes, that is required.",funFact:"Nötig implies urgency or obligation, stronger than 'brauchen' (to need). 'Es ist nötig, alle Dokumente mitzubringen.' The root is 'Not' (need/necessity), the same root as English 'need.'"},

{type:"teach",trg:"rechtzeitig",src:"on time, punctual",pos:"adj",gender:null,note:"Recht (right) + zeitig (timely). Arriving rechtzeitig at\nthe Behörde means arriving early.",example:"A: Sind Sie rechtzeitig gekommen?\nB: Ja, ich bin eine halbe Stunde früher da.\nA: Sehr gut. Pünktlichkeit ist wichtig.\nB: Das habe ich in Deutschland gelernt.",exampleSrc:"A: Did you come on time?\nB: Yes, I'm half an hour early.\nA: Very good. Punctuality is important.\nB: I learned that in Germany.",funFact:"Germans value Pünktlichkeit (punctuality). Arriving rechtzeitig at the Behörde means arriving early. Late? Your appointment may be gone. The word combines 'recht' (right) and 'zeitig' (timely)."},

{type:"fb",s:"Er muss einen {1} auf einen Aufenthaltstitel stellen.",a:["Antrag"],opts:["Antrag","Aufenthalt","Dokument","Visum"],hint:"Which word means a formal application filed at a government office?",sSrc:"He must file an application for a residence permit."},

{type:"teach",trg:"zunächst",src:"first of all, initially",pos:"adv",gender:null,note:"Zu (to) + nächst (nearest). A formal connector.\n'Zunächst müssen Sie das Formular ausfüllen.'",example:"A: Was muss ich zuerst machen?\nB: Zunächst füllen Sie das Formular aus.\nA: Und dann?\nB: Danach gehen Sie zum Schalter drei.",exampleSrc:"A: What do I have to do first?\nB: First of all, fill out the form.\nA: And then?\nB: After that, go to counter three.",funFact:"Zunächst is a formal word for 'first of all.' You hear it constantly in official instructions. 'Zunächst müssen Sie das Formular ausfüllen, danach die Gebühr bezahlen.'"},

{type:"teach",trg:"vorläufig",src:"provisional, temporary",pos:"adj",gender:null,note:"Vor (before) + läufig (running). Not yet final.\nA vorläufige Genehmigung = temporary approval.",example:"A: Ist der Aufenthaltstitel schon endgültig?\nB: Nein, zunächst ist er vorläufig.\nA: Wie lange gilt die vorläufige Genehmigung?\nB: Sechs Monate. Dann kommt die endgültige.",exampleSrc:"A: Is the residence permit already final?\nB: No, initially it is provisional.\nA: How long is the temporary approval valid?\nB: Six months. Then comes the final one.",funFact:"Many German permits start vorläufig before becoming endgültig (final). A vorläufige Genehmigung is a temporary approval. The word literally means 'pre-running,' something that comes before the real thing."},

{type:"teach",trg:"sicher",src:"safe, certain, sure",pos:"adj",gender:null,note:"From Latin 'securus' (without care). Two meanings:\n'Ich bin sicher' = I am sure. 'Das ist sicher' = safe/certain.",example:"A: Sind Sie sicher, dass alle Dokumente dabei sind?\nB: Ja, ganz sicher. Ich habe alles dreimal geprüft.\nA: Gut. Dann kann es losgehen.\nB: Ich bin sicher, dass alles in Ordnung ist.",exampleSrc:"A: Are you sure all documents are here?\nB: Yes, completely sure. I checked everything three times.\nA: Good. Then we can get started.\nB: I'm sure everything is in order.",funFact:"Sicher means both 'safe' and 'certain.' Context determines which. 'Ich bin sicher' = I am sure. 'Das ist sicher' = That is safe/certain. The word comes from Latin 'securus' (without care)."},

{type:"mc",q:"Alle Unterlagen müssen vor dem Termin gesammelt werden. Was sind Unterlagen?",opts:["Gebühren und anfallende Kosten","Termine und laufende Fristen","Formulare und Dokumente","Beamte und leitende Mitarbeiter"],ans:"Formulare und Dokumente",hint:"Unterlagen are the papers and documents you bring to an office."},

{type:"teach",trg:"danach",src:"after that, afterwards",pos:"adv",gender:null,note:"Da (there) + nach (after). A pronominal adverb.\n'Zunächst das Formular, danach die Gebühr bezahlen.'",example:"A: Zunächst den Antrag ausfüllen.\nB: Und danach?\nA: Danach bringen Sie alles zum Schalter.\nB: Verstanden. Erst das Formular, danach der Schalter.",exampleSrc:"A: First fill out the application.\nB: And after that?\nA: After that, bring everything to the counter.\nB: Understood. First the form, then the counter.",funFact:"Germans love sequencing with zunächst...danach...schließlich. Danach is a pronominal adverb (da + nach). It means 'after that' and is essential for following multi-step bureaucratic instructions."},

{type:"teach",trg:"die Bestätigung",src:"the confirmation",pos:"noun",gender:"f",note:"From 'bestätigen' (to confirm). Paper proof of anything.\n'Können Sie mir eine Bestätigung geben?'",example:"A: Kann ich eine Bestätigung bekommen?\nB: Ja, ich drucke Ihnen eine Bestätigung aus.\nA: Danke, die brauche ich für meinen Arbeitgeber.\nB: Bitte, hier ist Ihre Bestätigung.",exampleSrc:"A: Can I get a confirmation?\nB: Yes, I'll print out a confirmation for you.\nA: Thanks, I need it for my employer.\nB: Here you go, here is your confirmation.",funFact:"Every official action in Germany produces a Bestätigung. Paper proof is king. 'Können Sie mir eine Bestätigung geben?' is a phrase you will use again and again."},

{type:"teach",trg:"die Meldung",src:"the registration, the report",pos:"noun",gender:"f",note:"From 'melden' (to report/register). Die Anmeldung is\nthe residential registration every resident needs.",example:"A: Haben Sie Ihre Meldung schon gemacht?\nB: Ja, die Anmeldung habe ich letzte Woche erledigt.\nA: Gut, die Meldebescheinigung brauchen wir hier.\nB: Hier ist sie.",exampleSrc:"A: Have you done your registration yet?\nB: Yes, I completed the registration last week.\nA: Good, we need the registration certificate here.\nB: Here it is.",funFact:"The Anmeldung (residential registration) is the first Meldung every resident needs. No Meldung = no bank account, no insurance, no phone contract. The word comes from 'melden' (to report)."},


{type:"mc",q:"Verumius hat eine Wartenummer. Wo ist er?",opts:["In der Schule","Im Krankenhaus","Im Restaurant nebenan","In der Behörde"],ans:"In der Behörde",hint:"A place where you take a number and wait for government services."},

{type:"fb",s:"Verumius muss {1} alle Unterlagen sammeln.",a:["zunächst"],opts:["zunächst","danach","trotzdem","während"],hint:"Which word means 'first of all' when listing steps?",sSrc:"Verumius must first of all collect all the documents."},

{type:"mc",q:"Verumius hat eine vorläufige Genehmigung. Was bedeutet das?",opts:["Die Genehmigung ist temporär.","Die Genehmigung ist falsch.","Die Genehmigung ist endgültig.","Die Genehmigung ist abgelaufen."],ans:"Die Genehmigung ist temporär.",hint:"Vorläufig means something is not yet permanent."},


{type:"mc",q:"Welches Wort beschreibt etwas, das noch nicht endgültig ist?",opts:["rechtzeitig","vorläufig","danach","nötig"],ans:"vorläufig",hint:"Think of a permit that is temporary before becoming final."},
{type:"fb",s:"Er muss {1} das Formular ausfüllen und danach die Gebühr bezahlen.",a:["zunächst"],opts:["zunächst","sicher","vorläufig","nötig"],hint:"Which adverb means 'first of all' in a sequence of steps?",sSrc:"He must first of all fill out the form and then pay the fee."}
]},

// ===== LESSON 2: "Amtsdeutsch" (Official German) =====
// Vocab teach (bureaucracy + legal + family). 18 new words. 24 steps.
{id:"deu_r19l2",title:"Amtsdeutsch",icon:"\uD83D\uDCDC",xp:15,board:true,steps:[
{type:"intro",title:"Amtsdeutsch",desc:"The language of German administration: long, precise, and full of technical terms. Laws, fees, obligations. Welcome to the world of official German.",goals:["Learn bureaucratic vocabulary for government offices and law","Understand administrative terminology","Master vocabulary for citizenship and civic duties"]},
{type:"teach",trg:"die Gebühr",src:"the fee",pos:"noun",gender:"f",note:"From 'gebühren' (to be due). A government fee.\nDie Bearbeitungsgebühr = processing fee.",example:"A: Wie hoch ist die Gebühr für den Antrag?\nB: Die Gebühr beträgt 100 Euro.\nA: Kann ich mit Karte bezahlen?\nB: Nein, nur Überweisung oder Bargeld.",exampleSrc:"A: How much is the fee for the application?\nB: The fee is 100 euros.\nA: Can I pay by card?\nB: No, only bank transfer or cash.",funFact:"Die Bearbeitungsgebühr (processing fee) is attached to every Antrag. Germany never does paperwork for free. The word comes from 'gebühren' (to be due)."},
{type:"teach",trg:"die Urkunde",src:"the certificate",pos:"noun",gender:"f",note:"From Old High German 'urchundi' (testimony). Original only.\nGeburtsurkunde, Heiratsurkunde.",example:"A: Ich brauche eine beglaubigte Urkunde.\nB: Welche Urkunde genau?\nA: Die Geburtsurkunde.\nB: Bringen Sie bitte das Original mit.",exampleSrc:"A: I need a certified certificate.\nB: Which certificate exactly?\nA: The birth certificate.\nB: Please bring the original.",funFact:"Geburtsurkunde (birth certificate), Heiratsurkunde (marriage certificate). The word comes from Old High German 'urchundi' (testimony). Original documents only. Copies will not do."},
{type:"teach",trg:"das Gesetz",src:"the law",pos:"noun",gender:"n",note:"From 'setzen' (to set/place). Something 'set' in place.\n'Gesetz ist Gesetz' is a very German phrase.",example:"A: Was sagt das Gesetz dazu?\nB: Das Gesetz ist hier eindeutig.\nA: Gibt es Ausnahmen?\nB: Nein, Gesetz ist Gesetz.",exampleSrc:"A: What does the law say about that?\nB: The law is clear here.\nA: Are there exceptions?\nB: No, the law is the law.",funFact:"Das Grundgesetz is the German constitution. The word Gesetz comes from 'setzen' (to set in place). 'Gesetz ist Gesetz' (the law is the law) is a very German expression."},
{type:"teach",trg:"das Recht",src:"the right, the law",pos:"noun",gender:"n",note:"Same root as English 'right.' Both a right and the legal system.\n'Sie haben das Recht auf...' = you are entitled to...",example:"A: Habe ich das Recht auf einen Aufenthaltstitel?\nB: Ja, wenn alle Voraussetzungen erfüllt sind.\nA: Welche Rechte habe ich als Einwohner?\nB: Viele. Informieren Sie sich beim Amt.",exampleSrc:"A: Do I have the right to a residence permit?\nB: Yes, if all requirements are met.\nA: What rights do I have as a resident?\nB: Many. Inform yourself at the office.",funFact:"'Recht' means both a right (das Recht auf...) and the legal system (das Recht). 'Sie haben das Recht auf einen Aufenthaltstitel' means you are legally entitled to one."},
{type:"teach",trg:"die Pflicht",src:"the duty, the obligation",pos:"noun",gender:"f",note:"From Old High German 'pflihti' (care/duty).\nSchulpflicht, Versicherungspflicht. Germany runs on Pflichten.",example:"A: Was sind meine Pflichten als Einwohner?\nB: Sie müssen sich anmelden und Steuern zahlen.\nA: Gibt es noch andere Pflichten?\nB: Ja, die Versicherungspflicht zum Beispiel.",exampleSrc:"A: What are my duties as a resident?\nB: You must register and pay taxes.\nA: Are there other duties?\nB: Yes, mandatory insurance for example.",funFact:"Die Schulpflicht (compulsory education), die Versicherungspflicht (mandatory insurance). Germany runs on Pflichten. The word comes from Old High German 'pflihti' (care/duty)."},
{type:"fb",s:"Die {1} für den Antrag beträgt 100 Euro.",a:["Gebühr"],opts:["Gebühr","Urkunde","Pflicht","Herkunft"],hint:"Which word means a fee charged by a government office?",sSrc:"The fee for the application amounts to 100 euros."},
{type:"teach",trg:"die Herkunft",src:"the origin",pos:"noun",gender:"f",note:"Her- (from) + Kunft (coming). Where you come from.\nHerkunftsland = country of origin.",example:"A: Woher kommen Sie? Was ist Ihre Herkunft?\nB: Ich komme aus Griechenland.\nA: Und wie lange sind Sie schon in Deutschland?\nB: Seit zwei Jahren.",exampleSrc:"A: Where do you come from? What is your origin?\nB: I come from Greece.\nA: And how long have you been in Germany?\nB: For two years.",funFact:"The Behörde always asks about Herkunft. Herkunftsland = country of origin. Not the same as Heimat (which is emotional). Herkunft is factual, about geography and nationality."},
{type:"teach",trg:"die Integration",src:"the integration",pos:"noun",gender:"f",note:"Latin 'integratio' (renewal). The process of becoming\npart of society. Integrationskurse are mandatory for many.",example:"A: Haben Sie einen Integrationskurs besucht?\nB: Ja, 600 Stunden Deutsch und 100 Stunden Politik.\nA: Sehr gut. Das ist wichtig für die Integration.\nB: Es war anstrengend, aber hilfreich.",exampleSrc:"A: Have you attended an integration course?\nB: Yes, 600 hours of German and 100 hours of civics.\nA: Very good. That is important for integration.\nB: It was exhausting, but helpful.",funFact:"Germany has Integrationskurse (integration courses): 600 hours of German + 100 hours of civics. Mandatory for many immigrants. The concept of Integration is central to German immigration policy."},
{type:"teach",trg:"die Migration",src:"the migration",pos:"noun",gender:"f",note:"Latin 'migratio' (moving). Population movement as a concept.\nEinwanderung = immigration, Auswanderung = emigration.",example:"A: Migration ist ein globales Thema.\nB: Ja, Millionen Menschen migrieren jedes Jahr.\nA: Deutschland hat eine lange Migrationsgeschichte.\nB: Seit den 1960er-Jahren, mit den Gastarbeitern.",exampleSrc:"A: Migration is a global topic.\nB: Yes, millions of people migrate every year.\nA: Germany has a long history of migration.\nB: Since the 1960s, with the guest workers.",funFact:"Immigration (Einwanderung) and emigration (Auswanderung) are both types of Migration. Germany's Migrationsgeschichte goes back to the 1960s Gastarbeiter (guest workers) program."},
{type:"teach",trg:"der Migrant",src:"the migrant (male)",pos:"noun",gender:"m",note:"A person who migrates. Die Migrantin = female form.\nPlural 'Migranten' covers everyone.",example:"A: Wie viele Migranten leben in Berlin?\nB: Über eine Million Menschen haben Migrationshintergrund.\nA: Das ist fast ein Drittel der Bevölkerung.\nB: Berlin ist eine sehr diverse Stadt.",exampleSrc:"A: How many migrants live in Berlin?\nB: Over a million people have a migration background.\nA: That's almost a third of the population.\nB: Berlin is a very diverse city.",funFact:"German always has masculine and feminine forms: der Migrant, die Migrantin. The plural 'Migranten' covers everyone. Gender-specific titles are standard in official German."},
{type:"mc",q:"Was ist das Grundgesetz?",opts:["Die deutsche Verfassung","Ein Formular für das Amt","Ein Wohnort","Eine Urkunde"],ans:"Die deutsche Verfassung",hint:"Das Grundgesetz contains the fundamental laws and rights of Germany."}
]},
{id:"deu_r19l2b",title:"Amtsdeutsch (Teil 2)",icon:"\uD83D\uDCDC",xp:15,board:true,steps:[
{type:"intro",title:"Amtsdeutsch (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"die Verwaltung",src:"the administration",pos:"noun",gender:"f",note:"From 'verwalten' (to administer). Die Stadtverwaltung =\ncity administration. Verwaltungsakt = administrative act.",example:"A: Die Verwaltung hat meinen Antrag bearbeitet.\nB: Wie lange hat das gedauert?\nA: Sechs Wochen.\nB: Das ist für die deutsche Verwaltung ganz normal.",exampleSrc:"A: The administration processed my application.\nB: How long did that take?\nA: Six weeks.\nB: That's quite normal for the German administration.",funFact:"Germany's Verwaltung is legendarily thorough. Every process has a Verwaltungsakt (administrative act). Die Stadtverwaltung = city administration. The word comes from 'verwalten' (to administer)."},
{type:"teach",trg:"der Wohnort",src:"the place of residence",pos:"noun",gender:"m",note:"Wohn- (dwelling) + Ort (place). On every form.\nDifferent from Wohnsitz (official registered address).",example:"A: Was ist Ihr Wohnort?\nB: Berlin, Kreuzberg.\nA: Ist das auch Ihr offizieller Wohnsitz?\nB: Ja, ich bin dort angemeldet.",exampleSrc:"A: What is your place of residence?\nB: Berlin, Kreuzberg.\nA: Is that also your official registered address?\nB: Yes, I'm registered there.",funFact:"You can have a Wohnort without a Wohnsitz if you haven't registered yet. Wohnort = where you live. Wohnsitz = where you are officially registered. Both appear on every German form."},
{type:"teach",trg:"der Wohnsitz",src:"the official registered address",pos:"noun",gender:"m",note:"Wohn- (dwelling) + Sitz (seat). Your officially registered address.\nThe Anmeldung establishes your Wohnsitz.",example:"A: Haben Sie einen Wohnsitz in Deutschland?\nB: Ja, seit der Anmeldung letzte Woche.\nA: Gut. Ohne Wohnsitz geht hier nichts.\nB: Das habe ich schnell gelernt.",exampleSrc:"A: Do you have a registered address in Germany?\nB: Yes, since the registration last week.\nA: Good. Nothing works here without a registered address.\nB: I learned that quickly.",funFact:"Without a Wohnsitz, you legally do not live anywhere in Germany. No Wohnsitz means no bank account, no insurance, no phone contract. The Anmeldung (registration) establishes your Wohnsitz."},
{type:"teach",trg:"die Daten",src:"the data, personal details",pos:"noun",gender:"pl",note:"Latin 'data' (things given). Always plural in German.\nPersönliche Daten = personal data. Datenschutz = data protection.",example:"A: Bitte geben Sie Ihre persönlichen Daten an.\nB: Name, Geburtsdatum und Adresse?\nA: Ja, und Ihre Telefonnummer.\nB: Hier, alles ist ausgefüllt.",exampleSrc:"A: Please provide your personal data.\nB: Name, date of birth, and address?\nA: Yes, and your phone number.\nB: Here, everything is filled in.",funFact:"Daten is always plural in German. Persönliche Daten = personal data. Data protection (Datenschutz) is a near-sacred concept in Germany. The word comes from Latin 'data' (things given)."},
{type:"fb",s:"Die {1} bearbeitet Anträge und verwaltet Dokumente.",a:["Verwaltung"],opts:["Verwaltung","Herkunft","Migration","Integration"],hint:"Which word means administration, the process of managing official affairs?",sSrc:"The administration processes applications and manages documents."},
{type:"teach",trg:"rechtlich",src:"legal, juridical",pos:"adj",gender:null,note:"Recht + -lich. 'Rechtlich gesehen...' = legally speaking.\nDifferent from 'recht' (right) and 'rechts' (to the right).",example:"A: Ist das rechtlich erlaubt?\nB: Rechtlich gesehen, ja.\nA: Gibt es rechtliche Probleme?\nB: Nein, alles ist rechtlich in Ordnung.",exampleSrc:"A: Is that legally permitted?\nB: Legally speaking, yes.\nA: Are there legal problems?\nB: No, everything is legally in order.",funFact:"'Rechtlich gesehen...' (legally speaking...) is how officials introduce legal requirements. Different from 'recht' (right/correct) and 'rechts' (to the right). Three forms, three meanings."},
{type:"teach",trg:"endgültig",src:"final, definitive",pos:"adj",gender:null,note:"End- (final) + gültig (valid). Cannot be appealed normally.\nThe opposite of vorläufig.",example:"A: Ist die Entscheidung endgültig?\nB: Ja, der Bescheid ist endgültig.\nA: Kann ich noch Widerspruch einlegen?\nB: Nur innerhalb von vier Wochen.",exampleSrc:"A: Is the decision final?\nB: Yes, the ruling is final.\nA: Can I still file an objection?\nB: Only within four weeks.",funFact:"An endgültiger Bescheid (final decision) cannot be appealed through normal channels. The opposite of vorläufig. The word you want to hear at the Behörde."},
{type:"teach",trg:"verantwortlich",src:"responsible",pos:"adj",gender:null,note:"Ver- + Antwort (answer) + -lich. Literally 'answerable.'\n'Wer ist dafür verantwortlich?'",example:"A: Wer ist für diesen Fall verantwortlich?\nB: Frau Müller ist dafür verantwortlich.\nA: Kann ich mit ihr sprechen?\nB: Sie ist gerade in einer Besprechung.",exampleSrc:"A: Who is responsible for this case?\nB: Ms. Müller is responsible for it.\nA: Can I speak with her?\nB: She is currently in a meeting.",funFact:"The Behörde always wants to know who is verantwortlich. The word literally means 'answerable' (ver- + Antwort + -lich). 'Wer ist dafür verantwortlich?' is a key bureaucratic question."},
{type:"teach",trg:"zuständig",src:"responsible, in charge (jurisdictionally)",pos:"adj",gender:null,note:"Zu- + Stand + -ig. Competent for a specific matter.\n'Diese Behörde ist für Visa zuständig.'",example:"A: Sind Sie für Aufenthaltstitel zuständig?\nB: Nein, dafür ist Schalter drei zuständig.\nA: Und wer ist hier zuständig?\nB: Ich bin für Anmeldungen zuständig.",exampleSrc:"A: Are you in charge of residence permits?\nB: No, counter three is in charge of that.\nA: And who is in charge here?\nB: I'm in charge of registrations.",funFact:"Each office is zuständig for specific matters. Wrong Behörde? They send you to the zuständige one. 'Diese Behörde ist für Visa zuständig.' Zuständig means jurisdictionally responsible, not personally responsible."},
{type:"tip",title:"Amtsdeutsch: Die Sprache der Verwaltung",text:"German official language uses:\n\n1. Long compound nouns: Aufenthaltsgenehmigung, Bearbeitungsgebühr\n2. Passive constructions: 'wird bearbeitet' (is being processed)\n3. Formal vocabulary: erhalten instead of bekommen\n\nKey pattern: nouns are built from smaller parts.\nAufenthalts-genehmigungs-antrag = residence-permit-application.\nRead right to left for meaning: it is an Antrag (application)\nfor a Genehmigung (approval) of an Aufenthalt (stay).",deepDive:"Amtsdeutsch sounds different from everyday German because it evolved from legal Latin traditions. The long compound nouns are actually more precise than using multiple words. Each compound has exactly one meaning, leaving no room for ambiguity. This precision is intentional: in law, every word matters."},
{type:"mc",q:"Welches Wort bedeutet 'deadline'?",opts:["Frist","Pflicht","Gebühr","Recht"],ans:"Frist",hint:"This word refers to a time limit for submitting something."},
{type:"mc",q:"Was ist ein Wohnsitz?",opts:["Der Arbeitsplatz","Die offizielle Meldeadresse","Das Heimatland","Ein bequemer Stuhl"],ans:"Die offizielle Meldeadresse",hint:"Wohn- relates to living, Sitz relates to an official seat or registration."},
{type:"fb",s:"Die Ausländerbehörde ist für Visa {1}.",a:["zuständig"],opts:["zuständig","verantwortlich","endgültig","rechtlich"],hint:"Which adjective describes jurisdictional responsibility of an office?",sSrc:"The immigration office is in charge of visas."},
{type:"match",pairs:[{trg:"Gebühr",src:"fee"},{trg:"Urkunde",src:"certificate"},{trg:"Gesetz",src:"law"},{trg:"Pflicht",src:"duty"},{trg:"Verwaltung",src:"administration"}]},
{type:"mc",q:"Verumius braucht eine Geburtsurkunde. Was ist das?",opts:["Eine Bestätigung der Adresse","Ein Formular für die Schule","Ein offizielles Dokument über die Geburt","Ein Foto für den Pass"],ans:"Ein offizielles Dokument über die Geburt",hint:"This official document records the moment and place a person came into the world."},
{type:"mc",q:"Was bedeutet 'der Wohnort'?",opts:["responsible, in charge (jurisdictionally)","the law","responsible","the place of residence"],ans:"the place of residence",hint:"Wohn- (living) + Ort (location). Where you are officially registered."},
{type:"fb",s:"Wie sagt man 'the data, personal details' auf Deutsch? {1}",a:["die Daten"],opts:["zuständig","die Herkunft","die Daten","die Migration"],hint:"Cognate of English 'data.' Personal details on official forms.",sSrc:"How do you say 'the data, personal details' in German?"}
]},

// ===== LESSON 3: "Das muss gemacht werden" (That Must Be Done) =====
// Grammar: Passive with modals (#9). 14 new words. 22 steps.
{id:"deu_r19l3",title:"Das muss gemacht werden",icon:"\u2699\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Das muss gemacht werden",desc:"Passive with modal verbs: What must be done? What can be applied for? What must not be forgotten? The language of the government office, step by step.",goals:["Learn passive with modal verbs: muss/kann/soll/darf + Partizip II + werden","Express obligations, permissions, and prohibitions","Use bureaucratic German with confidence"]},


{type:"teach",trg:"beantragen",src:"to apply for (officially)",pos:"verb",gender:null,note:"Be- + Antrag + -en. To apply for something at an office.\n'Einen Aufenthaltstitel beantragen.'",example:"A: Was möchten Sie beantragen?\nB: Ich möchte einen Aufenthaltstitel beantragen.\nA: Haben Sie alle Unterlagen?\nB: Ja, alles ist vollständig.",exampleSrc:"A: What would you like to apply for?\nB: I would like to apply for a residence permit.\nA: Do you have all the documents?\nB: Yes, everything is complete.",funFact:"The be- prefix makes it transitive: you beantragen something directly. 'Einen Aufenthaltstitel beantragen' is what Verumius is doing right now. Without be-, Antrag is just the noun."},

{type:"teach",trg:"genehmigen",src:"to approve, to grant permission",pos:"verb",gender:null,note:"From 'genehm' (agreeable). To approve officially.\n'Der Antrag wurde genehmigt.' = the golden words.",example:"A: Wurde mein Antrag genehmigt?\nB: Ja, Ihr Antrag wurde genehmigt.\nA: Wirklich? Das ist eine gute Nachricht!\nB: Herzlichen Glückwunsch.",exampleSrc:"A: Was my application approved?\nB: Yes, your application was approved.\nA: Really? That's great news!\nB: Congratulations.",funFact:"'Der Antrag wurde genehmigt' is the sentence every applicant wants to hear. Die Genehmigung = the approval. The word comes from 'genehm' (agreeable)."},

{type:"teach",trg:"ausstellen",src:"to issue (a document)",pos:"verb",gender:null,note:"Aus- (out) + stellen (to place). To issue officially.\n'Einen Pass ausstellen' = to issue a passport.",example:"A: Wo wird der Aufenthaltstitel ausgestellt?\nB: Am Schalter fünf.\nA: Wie lange dauert das Ausstellen?\nB: Etwa 20 Minuten.",exampleSrc:"A: Where is the residence permit issued?\nB: At counter five.\nA: How long does the issuing take?\nB: About 20 minutes.",funFact:"The Behörde stellt Dokumente aus. Without ausstellen, no official paper exists. Separable verb: 'Sie stellt den Pass aus.' In passive: 'Der Pass wird ausgestellt.'"},

{type:"teach",trg:"verlängern",src:"to extend, to renew",pos:"verb",gender:null,note:"Ver- + länger (longer) + -n. To make something last longer.\n'Das Visum verlängern' = to extend the visa.",example:"A: Ich muss mein Visum verlängern.\nB: Wann läuft es ab?\nA: In drei Wochen.\nB: Dann stellen Sie schnell einen Antrag.",exampleSrc:"A: I need to extend my visa.\nB: When does it expire?\nA: In three weeks.\nB: Then file an application quickly.",funFact:"Every permit has an expiry date. Verlängern before the Frist. Always. The word literally means 'to make longer' (ver- + länger)."},

{type:"teach",trg:"anerkennen",src:"to officially recognize",pos:"verb",gender:null,note:"An- (at) + erkennen (to recognize). To recognize officially.\n'Einen Abschluss anerkennen' = to recognize a degree.",example:"A: Wird mein Diplom in Deutschland anerkannt?\nB: Das hängt vom Fach ab.\nA: Ich habe Informatik studiert.\nB: Informatik wird meistens anerkannt.",exampleSrc:"A: Is my diploma recognized in Germany?\nB: That depends on the subject.\nA: I studied computer science.\nB: Computer science is usually recognized.",funFact:"Foreign qualifications must be anerkannt (recognized) in Germany before they count. The process is called Anerkennung. Without it, your degree is just a piece of paper."},

{type:"mc",q:"Verumius möchte sein Visum verlängern. Was bedeutet das?",opts:["Er will es länger gültig machen","Er will es kürzer machen","Er will ein neues bekommen","Er will es abgeben"],ans:"Er will es länger gültig machen",hint:"The verb means to extend the validity of something. Think of it as adding more time."},

{type:"teach",trg:"erhalten",src:"to receive (formal)",pos:"verb",gender:null,note:"Er- + halten (to hold). Formal register for 'to receive.'\n'Sie erhalten den Bescheid per Post.'",example:"A: Wann erhalte ich den Bescheid?\nB: Sie erhalten ihn innerhalb von sechs Wochen.\nA: Per Post oder per E-Mail?\nB: Per Post, als Einschreiben.",exampleSrc:"A: When will I receive the decision?\nB: You will receive it within six weeks.\nA: By mail or by email?\nB: By mail, as registered post.",funFact:"In official German, erhalten replaces bekommen (to get). Same meaning, higher register. 'Sie erhalten den Bescheid per Post.' You see erhalten on every official letter."},

{type:"teach",trg:"enthalten",src:"to contain",pos:"verb",gender:null,note:"Ent- + halten (to hold). What is inside something.\nNot to be confused with erhalten (receive).",example:"A: Was enthält der Antrag?\nB: Er enthält alle persönlichen Daten.\nA: Ist die Geburtsurkunde enthalten?\nB: Ja, alle Unterlagen sind enthalten.",exampleSrc:"A: What does the application contain?\nB: It contains all personal data.\nA: Is the birth certificate included?\nB: Yes, all documents are included.",funFact:"Enthalten = what is inside. Erhalten = what you get. Same root (halten = to hold), different prefixes, very different meanings. A common source of confusion for learners."},

{type:"teach",trg:"verpflichten",src:"to obligate",pos:"verb",gender:null,note:"Ver- + Pflicht + -en. When the Behörde says verpflichtet,\nit is not a suggestion. It is the law.",example:"A: Sind wir verpflichtet, einen Integrationskurs zu machen?\nB: Ja, Sie sind gesetzlich dazu verpflichtet.\nA: Was passiert, wenn ich nicht teilnehme?\nB: Es gibt Konsequenzen für Ihren Aufenthalt.",exampleSrc:"A: Are we obligated to take an integration course?\nB: Yes, you are legally obligated to do so.\nA: What happens if I don't attend?\nB: There are consequences for your residence status.",funFact:"When the Behörde says verpflichtet, it is not a suggestion. It is the law. The word combines ver- (intensifier) + Pflicht (duty) + -en (verb ending)."},

{type:"teach",trg:"fällig",src:"due, payable",pos:"adj",gender:null,note:"From 'fallen' (to fall due). The deadline has arrived.\n'Die Gebühr ist sofort fällig.'",example:"A: Wann ist die Gebühr fällig?\nB: Die Gebühr ist sofort fällig.\nA: Kann ich auch nächste Woche bezahlen?\nB: Nein, sofort fällig bedeutet sofort.",exampleSrc:"A: When is the fee due?\nB: The fee is due immediately.\nA: Can I also pay next week?\nB: No, due immediately means immediately.",funFact:"When something is fällig, the deadline has arrived. No more waiting. 'Die Gebühr ist sofort fällig.' The word comes from 'fallen' (to fall due)."},

{type:"teach",trg:"zusätzlich",src:"additional",pos:"adj",gender:null,note:"Zu- (to) + Satz (set) + -lich. The word you do not want\nto hear at the Behörde: it means more paperwork.",example:"A: Brauchen Sie zusätzliche Dokumente?\nB: Ja, wir brauchen zusätzlich eine Meldebescheinigung.\nA: Die habe ich nicht dabei.\nB: Dann müssen Sie noch einmal kommen.",exampleSrc:"A: Do you need additional documents?\nB: Yes, we additionally need a registration certificate.\nA: I don't have that with me.\nB: Then you'll have to come again.",funFact:"The word you do not want to hear at the Behörde. 'Zusätzliche Dokumente sind erforderlich' means more paperwork, more time, more waiting."},

{type:"fb",s:"Der Antrag wurde {1}. Verumius darf jetzt bleiben.",a:["genehmigt"],opts:["genehmigt","verpflichtet","enthalten","beantragt"],hint:"Which past participle means the application was approved?",sSrc:"The application was approved. Verumius may now stay."},

{type:"teach",trg:"untersagt",src:"forbidden, prohibited",pos:"adj",gender:null,note:"Unter- + sagen (to say). Stronger than 'verboten.'\nUsed in official documents and formal contexts.",example:"A: Darf ich hier ohne Genehmigung arbeiten?\nB: Nein, das ist streng untersagt.\nA: Was passiert, wenn jemand trotzdem arbeitet?\nB: Es gibt hohe Strafen.",exampleSrc:"A: Am I allowed to work here without a permit?\nB: No, that is strictly prohibited.\nA: What happens if someone works anyway?\nB: There are heavy penalties.",funFact:"Stronger than 'verboten.' 'Das Arbeiten ist ohne Genehmigung untersagt.' Official German prefers untersagt in formal documents. Unter- + sagen literally means 'to say against.'"},

{type:"teach",trg:"voraussichtlich",src:"presumably, expected",pos:"adj",gender:null,note:"Voraus (ahead) + sichtlich (visibly). Bureaucratic hedging.\n'Voraussichtlich sechs Wochen.' No guarantees.",example:"A: Wie lange dauert die Bearbeitung?\nB: Voraussichtlich sechs Wochen.\nA: Kann es auch schneller gehen?\nB: Voraussichtlich nicht, aber manchmal passiert es.",exampleSrc:"A: How long does processing take?\nB: Presumably six weeks.\nA: Could it be faster?\nB: Presumably not, but sometimes it happens.",funFact:"Bureaucratic hedging: they expect it, but no guarantees. 'Die Bearbeitung dauert voraussichtlich sechs Wochen.' Voraus (ahead) + sichtlich (visibly) = 'as far as can be seen ahead.'"},

{type:"teach",trg:"inklusive",src:"including (casual)",pos:"prep",gender:null,note:"From Latin. Casual form of 'including.'\nEinschließlich is the formal German equivalent.",example:"A: Was kostet der Antrag?\nB: 100 Euro, inklusive Bearbeitungsgebühr.\nA: Sind die Passfotos inklusive?\nB: Nein, die müssen Sie selbst mitbringen.",exampleSrc:"A: How much does the application cost?\nB: 100 euros, including processing fee.\nA: Are passport photos included?\nB: No, you have to bring those yourself.",funFact:"Both inklusive and einschließlich mean 'including.' Inklusive is from Latin (casual). Einschließlich is the German compound (formal). Same meaning, different register."},

{type:"teach",trg:"einschließlich",src:"including (formal)",pos:"prep",gender:null,note:"Ein- + schließlich. Formal German for 'including.'\n'Einschließlich aller Unterlagen.'",example:"A: Welche Kosten fallen an?\nB: 150 Euro, einschließlich aller Gebühren.\nA: Gibt es versteckte Kosten?\nB: Nein, alles ist einschließlich.",exampleSrc:"A: What costs are there?\nB: 150 euros, including all fees.\nA: Are there hidden costs?\nB: No, everything is included.",funFact:"Einschließlich is the formal German compound for 'including.' You see it on every official document. 'Einschließlich aller Unterlagen' = including all paperwork."},

{type:"tip",title:"Passiv mit Modalverben: Wer macht was?",text:"You already know the passive with werden and Partizip II. Now add a modal verb.\n\nThe modal verb takes the second position in the sentence. The Partizip II and werden go to the end, with werden last.\n\n- Das Formular muss ausgefüllt werden. (The form must be filled out.)\n- Der Antrag kann online gestellt werden. (The application can be filed online.)\n- Das Dokument darf nicht kopiert werden. (The document may not be copied.)\n\nAll modals work this way: muss, kann, soll, darf, will.",deepDive:"In a Nebensatz (subordinate clause), the modal goes to the very end, after werden:\n\n'Ich weiß, dass das Formular ausgefüllt werden muss.'\n\nThe order is: Partizip II + werden + modal.\nThis triple verb cluster at the end is typical of German subordinate clauses and sounds complex, but the pattern is always the same."},

{type:"verb_table",title:"Passiv mit Modalverben",groups:[{label:"Beispiele mit verschiedenen Modalverben",rows:[{pronoun:"müssen",form:"Das Formular muss ausgefüllt werden.",src:"The form must be filled out."},{pronoun:"können",form:"Der Antrag kann online gestellt werden.",src:"The application can be filed online."},{pronoun:"sollen",form:"Die Gebühr soll überwiesen werden.",src:"The fee should be transferred."},{pronoun:"dürfen",form:"Das Dokument darf nicht kopiert werden.",src:"The document may not be copied."},{pronoun:"wollen",form:"Der Termin will verschoben werden.",src:"The appointment is to be rescheduled."}]}],note:"Modal in V2 position. Partizip II before werden at the end. Always."},

{type:"mc",q:"Das Visum _____ verlängert werden.",opts:["hat","muss","ist","wird"],ans:"muss",hint:"Which modal verb expresses obligation? The structure is modal + PP + werden."},

{type:"mc",q:"Welcher Satz hat die richtige Wortstellung?",opts:["Kann der Antrag gestellt online werden.","Der Antrag online gestellt werden kann.","Der Antrag kann online gestellt werden.","Der Antrag kann nicht online gestellt werden."],ans:"Der Antrag kann online gestellt werden.",hint:"The modal sits in position two. The past participle and the passive auxiliary go at the end."},

{type:"fb",s:"Der Pass {1} am Schalter abgeholt werden.",a:["kann"],opts:["kann","muss","wird","hat"],hint:"Which modal expresses ability or permission?",sSrc:"The passport can be picked up at the counter."},

{type:"mc",q:"Wie sagt man 'Working without a permit is not allowed' im Passiv?",opts:["Arbeiten ist ohne Genehmigung nicht möglich.","Ohne Genehmigung wird nicht gearbeitet.","Ohne Genehmigung muss vorher eine Erlaubnis eingeholt werden.","Ohne Genehmigung darf nicht gearbeitet werden."],ans:"Ohne Genehmigung darf nicht gearbeitet werden.",hint:"The sentence expresses prohibition, not just absence. Which modal verb signals that something is not permitted?"},

{type:"drag_fill",s:"Die Unterlagen {1} rechtzeitig {2} {3}.",blanks:{"1":"müssen","2":"eingereicht","3":"werden"},pool:["müssen","eingereicht","werden","muss","einreichen","wird"],hint:"Three blanks: first the obligation modal for a plural subject, then the past participle of 'einreichen', then the passive auxiliary.",sSrc:"The documents must be submitted on time."},


{type:"mc",q:"Verumius fragt: 'Kann der Antrag auch online gestellt werden?' Was will er wissen?",opts:["Ob er den Antrag digital einreichen kann","Ob der Antrag genehmigt wurde","Wann genau die Frist für den Antrag abläuft","Wie viel der Antrag bei der Behörde kostet"],ans:"Ob er den Antrag digital einreichen kann",hint:"He inquires about an alternative way to submit. The word 'online' points to an electronic channel."},

{type:"mc",q:"Die Miete ist am ersten des Monats fällig. Was bedeutet 'fällig'?",opts:["optional","due, payable","free of charge","delayed"],ans:"due, payable",hint:"Something that must be paid by a certain date is this word."},

{type:"fb",s:"Für den Antrag braucht man {1} Dokumente.",a:["zusätzlich","zusätzliche"],opts:["zusätzliche","notwendige","fehlende","vorherige"],hint:"These documents are extra, on top of what you already have.",sSrc:"For the application you need additional documents."},

{type:"mc",q:"Der Bescheid kommt voraussichtlich in zwei Wochen. Was bedeutet 'voraussichtlich'?",opts:["immediately","certainly","presumably, expected","unfortunately"],ans:"presumably, expected",hint:"It expresses an estimate about when something will likely happen."},

{type:"fb",s:"Die Gebühren sind {1} Bearbeitungskosten.",a:["inklusive"],opts:["inklusive","ohne","trotz","neben"],hint:"The fees already contain the processing costs inside them.",sSrc:"The fees are including processing costs."}
]},

// ===== LESSON 4: "Bevor die Frist abläuft" (Before the Deadline Expires) =====
// Grammar: Subordinating conjunctions expanded (#18). 16 new words. 24 steps.
{id:"deu_r19l4",title:"Bevor die Frist abläuft",icon:"\u23F0",xp:15,board:true,steps:[
{type:"intro",title:"Bevor die Frist abläuft",desc:"Eight new conjunctions. Time, purpose, condition, concession. Complex sentences for official situations. The verb goes to the end.",goals:["Learn 8 new subordinating conjunctions","Express time, purpose, condition, and concession","Build complex German sentences for official contexts"]},
{type:"teach",trg:"obwohl",src:"although",pos:"conj",gender:null,note:"Ob (whether) + wohl (well). Introduces a concession.\nVerb goes to the END of the obwohl-clause.",example:"A: Obwohl er nervös war, hatte er alle Dokumente.\nB: Das ist beeindruckend.\nA: Obwohl die Frist kurz war, hat er alles geschafft.\nB: Gute Vorbereitung ist alles.",exampleSrc:"A: Although he was nervous, he had all documents.\nB: That's impressive.\nA: Although the deadline was short, he managed everything.\nB: Good preparation is everything.",funFact:"Obwohl always sends the verb to the end of its clause. 'Obwohl er nervös war, hatte er alle Dokumente.' It introduces a concession: something is true despite another fact."},
{type:"teach",trg:"trotzdem",src:"nevertheless, despite that",pos:"adv",gender:null,note:"Trotz (despite) + dem (that). NOT a conjunction but an adverb.\nTrotzdem takes V2 position in its clause.",example:"A: Er war nervös.\nB: Trotzdem hatte er alle Dokumente.\nA: Die Frist war kurz.\nB: Trotzdem hat er alles geschafft.",exampleSrc:"A: He was nervous.\nB: Nevertheless, he had all documents.\nA: The deadline was short.\nB: Nevertheless, he managed everything.",funFact:"Trotzdem is NOT a conjunction but an adverb. 'Er war nervös. Trotzdem hatte er alle Dokumente.' Trotzdem takes V2 position in its clause. Compare: obwohl = verb-final, trotzdem = verb-second."},
{type:"teach",trg:"bevor",src:"before",pos:"conj",gender:null,note:"Be- + vor (before). The bevor-clause describes what\nhas NOT happened yet. Verb-final.",example:"A: Bevor die Frist abläuft, muss alles eingereicht sein.\nB: Wann läuft die Frist ab?\nA: Am Freitag.\nB: Dann haben wir noch drei Tage.",exampleSrc:"A: Before the deadline expires, everything must be submitted.\nB: When does the deadline expire?\nA: On Friday.\nB: Then we still have three days.",funFact:"The bevor-clause describes what has NOT happened yet. 'Bevor die Frist abläuft, müssen alle Dokumente eingereicht werden.' Verb goes to the end of the bevor-clause."},
{type:"teach",trg:"seitdem",src:"since (a point in time)",pos:"conj",gender:null,note:"Seit (since) + dem (that). Marks the starting point\nof an ongoing situation. Verb-final.",example:"A: Seitdem ich in Berlin wohne, lerne ich Deutsch.\nB: Und wie lange wohnst du schon hier?\nA: Seitdem ich den Job bekommen habe.\nB: Das sind schon fast zwei Jahre.",exampleSrc:"A: Since I've been living in Berlin, I've been learning German.\nB: And how long have you been living here?\nA: Since I got the job.\nB: That's almost two years already.",funFact:"Seitdem marks the starting point of an ongoing situation. 'Seitdem ich in Berlin wohne, lerne ich Deutsch.' The conjunction version always takes verb-final word order."},
{type:"mc",q:"Welches Wort leitet eine Konzession ein? Etwas ist wahr, trotz einer anderen Tatsache.",opts:["obwohl","seitdem","trotzdem","bevor"],ans:"obwohl",hint:"This conjunction means although and sends the verb to the end."},
{type:"teach",trg:"bis",src:"until",pos:"conj",gender:null,note:"Old High German 'biz.' Marks the endpoint. Short, powerful.\n'Warten Sie, bis Ihre Nummer aufgerufen wird.'",example:"A: Warten Sie bitte, bis Ihre Nummer aufgerufen wird.\nB: Wie lange dauert das noch?\nA: Bis Nummer B089 dran ist, vielleicht eine Stunde.\nB: Ich warte, bis es so weit ist.",exampleSrc:"A: Please wait until your number is called.\nB: How much longer will that take?\nA: Until number B089 comes up, maybe an hour.\nB: I'll wait until it's time.",funFact:"'Bis' is short and powerful: 'Warten Sie, bis Ihre Nummer aufgerufen wird.' It marks the endpoint. Used constantly in bureaucratic instructions."},
{type:"teach",trg:"damit",src:"so that, in order that",pos:"conj",gender:null,note:"Da- (there) + mit (with). Different subjects allowed.\nVerb-final. 'Damit der Antrag bearbeitet werden kann' (So that the application can be processed).",example:"A: Bringen Sie alle Unterlagen mit.\nB: Warum?\nA: Damit der Antrag bearbeitet werden kann.\nB: Verstanden. Ich bringe alles mit.",exampleSrc:"A: Bring all documents with you.\nB: Why?\nA: So that the application can be processed.\nB: Understood. I'll bring everything.",funFact:"Damit expresses purpose: 'so that.' Different subjects are allowed (unlike um...zu). 'Bringen Sie alle Unterlagen mit, damit der Antrag bearbeitet werden kann.'"},
{type:"teach",trg:"falls",src:"in case, if (uncertain)",pos:"conj",gender:null,note:"From 'Fall' (case). More uncertain than 'wenn.'\nFalls = it might happen. Wenn = it probably will.",example:"A: Falls Sie Fragen haben, rufen Sie uns an.\nB: Was passiert, falls ich die Frist verpasse?\nA: Falls das passiert, müssen Sie einen neuen Antrag stellen.\nB: Dann passe ich auf die Frist auf.",exampleSrc:"A: In case you have questions, call us.\nB: What happens if I miss the deadline?\nA: If that happens, you must file a new application.\nB: Then I'll watch the deadline.",funFact:"Falls is more uncertain than 'wenn.' Falls = it might happen. Wenn = it probably will. Formal German prefers falls for conditions that may or may not occur."},
{type:"teach",trg:"während",src:"while, during",pos:"conj",gender:null,note:"From 'währen' (to last). Temporal overlap.\nAlso a preposition with genitive: während des Gesprächs.",example:"A: Während der Beamte die Dokumente prüft, wartet Verumius.\nB: Ist das normal?\nA: Ja, während der Prüfung muss man warten.\nB: Während ich warte, lese ich ein Buch.",exampleSrc:"A: While the officer checks the documents, Verumius waits.\nB: Is that normal?\nA: Yes, during the check you have to wait.\nB: While I wait, I read a book.",funFact:"Während is both a conjunction (while) and a preposition with genitive (during). As a conjunction: 'Während der Beamte prüft, wartet Verumius.' As a preposition: 'während des Gesprächs.'"},
{type:"fb",s:"Bringen Sie alle Unterlagen mit, {1} der Antrag bearbeitet werden kann.",a:["damit"],opts:["damit","falls","bis","bevor"],hint:"Which conjunction expresses purpose, meaning so that?",sSrc:"Bring all documents so that the application can be processed."},
{type:"teach",trg:"abhängen",src:"to depend on",pos:"verb",gender:null,note:"Ab- (from) + hängen (to hang). Always with 'von.'\n'Es hängt davon ab, ob...' = it depends on whether...",example:"A: Wird mein Antrag genehmigt?\nB: Das hängt von den Unterlagen ab.\nA: Wovon hängt es noch ab?\nB: Es hängt auch von der Bearbeitungszeit ab.",exampleSrc:"A: Will my application be approved?\nB: That depends on the documents.\nA: What else does it depend on?\nB: It also depends on the processing time.",funFact:"Always used with 'von': von etwas abhängen. 'Es hängt davon ab, ob alle Unterlagen vollständig sind.' The outcome is 'hanging from' a condition."},
{type:"teach",trg:"abstimmen",src:"to coordinate, to align",pos:"verb",gender:null,note:"Ab- (off) + stimmen (to be correct/to vote). In bureaucracy:\nalign, coordinate. Also: to vote (in politics).",example:"A: Sind die Unterlagen aufeinander abgestimmt?\nB: Ja, alles passt zusammen.\nA: Gut, das ist wichtig.\nB: Wir haben alles sorgfältig abgestimmt.",exampleSrc:"A: Are the documents coordinated with each other?\nB: Yes, everything fits together.\nA: Good, that is important.\nB: We coordinated everything carefully.",funFact:"In bureaucracy, everything must be abgestimmt (aligned, coordinated). 'Die Unterlagen müssen aufeinander abgestimmt sein.' The word also means 'to vote' in political contexts."},
{type:"teach",trg:"umgehen",src:"to handle, to deal with",pos:"verb",gender:null,note:"Um- (around) + gehen (to go). Separable: UMgehen = handle.\nInseparable: umGEHen = circumvent.",example:"A: Wie geht man mit der Verwaltung um?\nB: Geduldig und gut vorbereitet.\nA: Und wenn es Probleme gibt?\nB: Ruhig bleiben und höflich nachfragen.",exampleSrc:"A: How do you deal with the administration?\nB: Patiently and well prepared.\nA: And if there are problems?\nB: Stay calm and ask politely.",funFact:"Two meanings depending on stress. 'UMgehen' (separable) = to handle/deal with. 'umGEHen' (inseparable) = to circumvent. 'Wie geht man mit der Verwaltung um?' = How do you deal with the administration?"},
{type:"teach",trg:"sichern",src:"to secure, to safeguard",pos:"verb",gender:null,note:"From 'sicher' (safe/certain). To secure, protect, back up.\n'Sichern Sie Ihre Daten' = protect your data.",example:"A: Haben Sie Kopien Ihrer Unterlagen?\nB: Ja, ich habe alles gesichert.\nA: Gut. Man sollte immer Kopien sichern.\nB: Das hat mir Hildi beigebracht.",exampleSrc:"A: Do you have copies of your documents?\nB: Yes, I've secured everything.\nA: Good. One should always secure copies.\nB: Hildi taught me that.",funFact:"In bureaucratic context: make copies, store safely, have backups. 'Sichern Sie Ihre Daten.' Related to Sicherheit (security). Always have backup copies of every official document."},
{type:"mc",q:"Es hängt davon ab, ob alle Unterlagen vollständig sind. Was bedeutet abhängen von?",opts:["to turn away from","to depend on","to pick up from","to fall away from"],ans:"to depend on",hint:"Ab- + hängen. The outcome hangs from a condition."},

{type:"fb",s:"Die Termine müssen aufeinander {1} werden.",a:["abgestimmt"],opts:["abgestimmt","abgeholt","abgelehnt","abgeschlossen"],hint:"The appointments need to be coordinated so they fit together.",sSrc:"The appointments must be coordinated with each other."},

{type:"mc",q:"Haben Sie alle Dokumente gesichert? Was bedeutet 'sichern'?",opts:["to print","to delete","to secure, to safeguard","to lose"],ans:"to secure, to safeguard",hint:"From the adjective 'sicher' (safe). Making something safe."}
]},
{id:"deu_r19l4b",title:"Bevor die Frist abläuft (Teil 2)",icon:"\u23F0",xp:15,board:true,steps:[
{type:"intro",title:"Bevor die Frist abläuft (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"der Zugang",src:"the access",pos:"noun",gender:"m",note:"Zu- (to) + Gang (way/passage). Access to something.\n'Zugang zum Arbeitsmarkt' = access to the job market.",example:"A: Habe ich Zugang zum Arbeitsmarkt?\nB: Ja, mit dem Aufenthaltstitel haben Sie vollen Zugang.\nA: Und ohne?\nB: Ohne Aufenthaltstitel ist der Zugang eingeschränkt.",exampleSrc:"A: Do I have access to the job market?\nB: Yes, with the residence permit you have full access.\nA: And without?\nB: Without a residence permit, access is restricted.",funFact:"The Aufenthaltstitel determines your Zugang to many things in Germany: work, education, social services. Zu- (to) + Gang (way/passage) = the way to something."},
{type:"teach",trg:"die Rufnummer",src:"the phone number (formal)",pos:"noun",gender:"f",note:"Ruf (call) + Nummer (number). More formal than Telefonnummer.\nAlways appears on official forms.",example:"A: Wie ist Ihre Rufnummer?\nB: 030-5551234.\nA: Und Ihre Mobilnummer?\nB: 0170-9876543.",exampleSrc:"A: What is your phone number?\nB: 030-5551234.\nA: And your mobile number?\nB: 0170-9876543.",funFact:"More formal than Telefonnummer. On official forms, you always see Rufnummer. Die Rufnummer is feminine because Nummer is feminine."},
{type:"teach",trg:"der Zivilstand",src:"the marital status",pos:"noun",gender:"m",note:"Zivil (civil) + Stand (status). Germany uses Familienstand\nmore often. Ledig, verheiratet, geschieden, verwitwet.",example:"A: Was ist Ihr Zivilstand?\nB: Ledig.\nA: Und Ihre Staatsangehörigkeit?\nB: Griechisch.",exampleSrc:"A: What is your marital status?\nB: Single.\nA: And your nationality?\nB: Greek.",funFact:"Swiss/Austrian term; Germany uses Familienstand more often. Both appear on forms. Options: ledig (single), verheiratet (married), geschieden (divorced), verwitwet (widowed)."},
{type:"teach",trg:"das Original",src:"the original (document)",pos:"noun",gender:"n",note:"From Latin 'originalis.' The original, not a copy.\n'Bringen Sie bitte das Original mit.'",example:"A: Ist das eine Kopie oder das Original?\nB: Das ist das Original.\nA: Gut, wir brauchen immer das Original.\nB: Kopien werden nicht akzeptiert?",exampleSrc:"A: Is that a copy or the original?\nB: That is the original.\nA: Good, we always need the original.\nB: Copies are not accepted?",funFact:"German offices almost always require Originale. Copies are only accepted exceptionally. 'Bringen Sie bitte das Original mit' is something you hear at every Behörde."},
{type:"tip",title:"Nebensatzkonjunktionen: Verb ans Ende",text:"All subordinating conjunctions push the conjugated verb to the END of their clause.\n\nObwohl er nervös WAR.\nBevor die Frist ABLÄUFT.\nWährend der Beamte die Dokumente PRÜFT.\n\nThe main clause keeps normal V2 order.\nWhen the subordinate clause comes first, the main clause verb comes immediately after the comma:\n'Bevor die Frist abläuft, MUSS man den Antrag einreichen.'",deepDive:"Trotzdem is NOT a subordinating conjunction. It is an adverb and keeps V2 word order: 'Trotzdem HAT er alle Dokumente.'\n\nCompare:\n'Obwohl er nervös war, hatte er alle Dokumente.'\nvs.\n'Er war nervös. Trotzdem hatte er alle Dokumente.'\n\nSame meaning, different structure. Obwohl = verb-final clause. Trotzdem = verb-second in a new sentence."},
{type:"mc",q:"Obwohl er alle Dokumente _____, war er nervös.",opts:["hatte","hatte er","er hatte","hat"],ans:"hatte",hint:"After obwohl, the verb goes to the END. Subject + object + verb."},
{type:"mc",q:"_____ Sie Fragen haben, können Sie uns anrufen.",opts:["Bis","Falls","Trotzdem","Seitdem"],ans:"Falls",hint:"This conjunction means 'in case' or 'if (uncertain)'. It introduces a possibility."},
{type:"fb",s:"{1} ich in Deutschland lebe, brauche ich einen Aufenthaltstitel.",a:["Seitdem"],opts:["Seitdem","Bevor","Bis","Falls"],hint:"Which conjunction marks the starting point of an ongoing situation?",sSrc:"Since I've been living in Germany, I need a residence permit."},
{type:"mc",q:"Welches Satzpaar hat die gleiche Bedeutung?",opts:["Obwohl er müde war, ging er zur Behörde. / Trotzdem er müde war, ging er zur Behörde.","Obwohl er müde war, ging er zur Behörde. / Er ging trotzdem müde zur Behörde.","Obwohl er müde war, ging er zur Behörde. / Er war müde. Trotzdem ging er zur Behörde.","Obwohl er müde war, ging er zur Behörde. / Er war müde, trotzdem er ging zur Behörde."],ans:"Obwohl er müde war, ging er zur Behörde. / Er war müde. Trotzdem ging er zur Behörde.",hint:"One option uses a subordinating conjunction in a single sentence. The other uses a standalone adverb in position 1 of a new sentence."},
{type:"teach",trg:"ablaufen",src:"to expire / to run out",pos:"verb",gender:null,note:"Separable: läuft ab. Past: ist abgelaufen. Used for deadlines, visas, and time limits.",example:"A: Wann läuft mein Visum ab?\nB: In drei Monaten.\nA: So bald? Ich muss einen Antrag stellen.\nB: Ja, bevor es abläuft.",exampleSrc:"A: When does my visa expire?\nB: In three months.\nA: So soon? I need to submit an application.\nB: Yes, before it expires.",funFact:"'Ablaufen' literally means 'to run off' (ab = away, laufen = to run). Time runs away when a deadline expires. The same verb describes water draining from a sink."},
{type:"drag_fill",s:"{1} die Frist {2}, muss der Antrag eingereicht werden.",blanks:{"1":"Bevor","2":"abläuft"},pool:["Bevor","abläuft","Bis","ablauft","Nachdem","abgelaufen"],hint:"Which conjunction means 'before'? The verb goes to the end of the subordinate clause.",sSrc:"Before the deadline expires, the application must be submitted."},
{type:"mc",q:"Verumius bringt alle Unterlagen mit, _____ der Antrag bearbeitet werden kann.",opts:["obwohl","falls","bis","damit"],ans:"damit",hint:"Which conjunction expresses purpose: 'so that' something can happen?"},
{type:"mc",q:"Was bedeutet 'der Zugang'?",opts:["the access","although","to depend on","since (a point in time)"],ans:"the access",hint:"Zu- (to) + Gang (going). The way to reach something."},
{type:"fb",s:"Wie sagt man 'the phone number (formal)' auf Deutsch? {1}",a:["die Rufnummer"],opts:["bevor","ablaufen","die Rufnummer","abhängen"],hint:"Ruf (call) + Nummer (number). The formal word for a phone contact.",sSrc:"How do you say 'the phone number (formal)' in German?"},
{type:"mc",q:"Was bedeutet 'der Zivilstand'?",opts:["to expire / to run out","the marital status","the access","since (a point in time)"],ans:"the marital status",hint:"Zivil (civil) + Stand (standing/position). Single, married, or divorced."},
{type:"fb",s:"Ist das eine Kopie oder {1}?",a:["das Original"],opts:["trotzdem","der Zivilstand","damit","das Original"],hint:"Same word in English. The authentic version, not a Kopie.",sSrc:"Is that a copy or the original?"},
{type:"mc",q:"Was bedeutet 'ablaufen'?",opts:["so that, in order that","until","to expire / to run out","since (a point in time)"],ans:"to expire / to run out",hint:"Ab- (away) + laufen (to flow). Time drains away from a document's validity."}
]},

// ===== LESSON 5: "Die Dokumentenprüfung" (The Document Check) =====
// Story development + combo practice. 15 new words. 22 steps.
{id:"deu_r19l5",title:"Die Dokumentenprüfung",icon:"\uD83D\uDD0D",xp:15,board:true,steps:[
{type:"intro",title:"Die Dokumentenprüfung",desc:"The clerk checks every document. Verumius waits. Passive with modal verbs and subordinate clauses in practice. Bureaucracy live.",goals:["Practice passive with modal verbs in a government office dialogue","Combine conjunctions with complex grammar","Navigate a document check at the government office"]},
{type:"teach",trg:"die Beamtin",src:"the civil servant (female)",pos:"noun",gender:"f",note:"Feminine form of Beamter. Civil servants in Germany\nhave lifelong job security and their own pension system.",example:"A: Die Beamtin prüft Ihre Unterlagen.\nB: Wie lange dauert das?\nA: Die Beamtin arbeitet gründlich, das dauert etwas.\nB: Ich warte geduldig.",exampleSrc:"A: The civil servant is checking your documents.\nB: How long will that take?\nA: The civil servant works thoroughly, it takes a while.\nB: I'll wait patiently.",funFact:"In Germany, Beamte have special status: job security for life, their own pension system, no right to strike. The person behind the desk at the Behörde is almost always a Beamter or Beamtin."},
{type:"teach",trg:"das Asyl",src:"the asylum",pos:"noun",gender:"n",note:"From Greek 'asylon' (sanctuary). Political asylum.\nGuaranteed in Germany's Grundgesetz, Article 16a.",example:"A: Was bedeutet Asyl?\nB: Asyl ist Schutz für politisch Verfolgte.\nA: Ist das Recht auf Asyl im Grundgesetz?\nB: Ja, in Artikel 16a.",exampleSrc:"A: What does asylum mean?\nB: Asylum is protection for politically persecuted people.\nA: Is the right to asylum in the constitution?\nB: Yes, in Article 16a.",funFact:"Das Asylrecht (right to asylum) is guaranteed in Germany's Grundgesetz, Article 16a. The word comes from Greek 'asylon' (sanctuary). A foundational principle of German democracy."},
{type:"teach",trg:"die Geburt",src:"the birth",pos:"noun",gender:"f",note:"From 'gebären' (to give birth). Root of many compounds:\nGeburtsurkunde, Geburtsort, Geburtsdatum.",example:"A: Was ist Ihr Geburtsdatum?\nB: Der 15. Mai 1990.\nA: Und Ihr Geburtsort?\nB: Athen, Griechenland.",exampleSrc:"A: What is your date of birth?\nB: May 15, 1990.\nA: And your place of birth?\nB: Athens, Greece.",funFact:"One root word, many compounds: die Geburtsurkunde (birth certificate), der Geburtsort (birthplace), das Geburtsdatum (date of birth). German builds precise meaning by combining words."},
{type:"teach",trg:"die Schwangerschaft",src:"the pregnancy",pos:"noun",gender:"f",note:"Schwanger (pregnant) + -schaft (state of).\nTriggers special protections: Mutterschutz, Kündigungsschutz.",example:"A: Gibt es besondere Regelungen bei Schwangerschaft?\nB: Ja, Schwangerschaft bedeutet besonderen Schutz.\nA: Mutterschutz und Kündigungsschutz?\nB: Genau, beides ist gesetzlich garantiert.",exampleSrc:"A: Are there special regulations for pregnancy?\nB: Yes, pregnancy means special protection.\nA: Maternity protection and termination protection?\nB: Exactly, both are guaranteed by law.",funFact:"In Germany, Schwangerschaft triggers special protections: Mutterschutz (maternity protection), Kündigungsschutz (termination protection). The Behörde tracks this information."},
{type:"teach",trg:"der Einwohner",src:"the resident, the inhabitant (male)",pos:"noun",gender:"m",note:"Ein- (in) + Wohner (dweller). Die Einwohnerin = female.\nDifferent from Bürger (citizen): Einwohner includes everyone.",example:"A: Wie viele Einwohner hat Berlin?\nB: Etwa 3,7 Millionen Einwohner.\nA: Bin ich jetzt auch ein Einwohner?\nB: Ja, mit der Anmeldung sind Sie offiziell Einwohner.",exampleSrc:"A: How many inhabitants does Berlin have?\nB: About 3.7 million inhabitants.\nA: Am I also a resident now?\nB: Yes, with the registration you are officially a resident.",funFact:"Different from Bürger (citizen): Einwohner includes everyone who lives there, regardless of citizenship. Das Einwohnermeldeamt is where you register."},
{type:"fb",s:"Das Recht auf {1} steht im Grundgesetz, Artikel 16a.",a:["Asyl"],opts:["Asyl","Geburt","Lager","Botschaft"],hint:"Which word refers to political protection for persecuted people?",sSrc:"The right to asylum is in the constitution, Article 16a."},
{type:"teach",trg:"das Lager",src:"the camp, the warehouse",pos:"noun",gender:"n",note:"From 'lagern' (to store/camp). In immigration context:\nErstaufnahmelager = initial reception camp.",example:"A: Was ist ein Erstaufnahmelager?\nB: Ein Lager für neue Asylbewerber.\nA: Wie lange bleibt man dort?\nB: Bis ein Platz in einer Wohnung frei wird.",exampleSrc:"A: What is an initial reception camp?\nB: A camp for new asylum seekers.\nA: How long does one stay there?\nB: Until a place in an apartment becomes available.",funFact:"Historically loaded word in German. In immigration context: Erstaufnahmelager (initial reception camp). Modern usage is primarily logistical. The word simply means a place where things or people are stored/housed."},
{type:"teach",trg:"das Konsulat",src:"the consulate",pos:"noun",gender:"n",note:"Handles visas and documents for citizens abroad.\nEvery large city has consulates of many countries.",example:"A: Brauche ich eine Bescheinigung vom Konsulat?\nB: Ja, das Konsulat Ihres Heimatlandes muss das ausstellen.\nA: Wo ist das griechische Konsulat?\nB: In der Wittenbergplatz-Straße.",exampleSrc:"A: Do I need a certificate from the consulate?\nB: Yes, the consulate of your home country must issue that.\nA: Where is the Greek consulate?\nB: On Wittenbergplatz Street.",funFact:"Das Konsulat handles visas and documents for citizens abroad. Die Botschaft (embassy) handles diplomatic relations. Every country has a Botschaft in Berlin. Botschaft also means 'message' in everyday German."},
{type:"teach",trg:"die Botschaft",src:"the embassy, the message",pos:"noun",gender:"f",note:"COMPOUND: Bot (message) + schaft (domain).\nTwo meanings: embassy (diplomatic) and message (everyday).\n'Die griechische Botschaft in Berlin.'",example:"A: Ich muss zur Botschaft.\nB: Zur griechischen Botschaft?\nA: Ja, für ein Dokument.\nB: Die Botschaft ist in Charlottenburg.",exampleSrc:"A: I need to go to the embassy.\nB: To the Greek embassy?\nA: Yes, for a document.\nB: The embassy is in Charlottenburg.",funFact:"Botschaft means both 'embassy' and 'message.' 'Die Botschaft des Botschafters' could mean 'the message of the ambassador' or 'the embassy of the ambassador.' Context makes it clear."},
{type:"teach",trg:"ausschließen",src:"to exclude, to rule out",pos:"verb",gender:null,note:"Aus- (out) + schließen (to close). To close out, exclude.\n'Das kann nicht ausgeschlossen werden.'",example:"A: Kann ein Fehler ausgeschlossen werden?\nB: Nein, Fehler können nie ganz ausgeschlossen werden.\nA: Was machen wir, falls ein Fehler auftaucht?\nB: Dann korrigieren wir ihn sofort.",exampleSrc:"A: Can an error be ruled out?\nB: No, errors can never be completely ruled out.\nA: What do we do if an error comes up?\nB: Then we correct it immediately.",funFact:"In legal German: possibilities are ausgeschlossen (ruled out) or not. 'Das kann nicht ausgeschlossen werden' is a careful bureaucratic way of saying 'it's possible.'"},
{type:"teach",trg:"empfangen",src:"to receive (formal)",pos:"verb",gender:null,note:"Emp- + fangen (to catch). Higher register than bekommen\nor erhalten. Used in official correspondence.",example:"A: Haben Sie den Bescheid empfangen?\nB: Ja, ich habe ihn gestern empfangen.\nA: Gut, dann können wir weitermachen.\nB: Ich habe auch die Bestätigung empfangen.",exampleSrc:"A: Have you received the decision?\nB: Yes, I received it yesterday.\nA: Good, then we can proceed.\nB: I also received the confirmation.",funFact:"Higher register than bekommen or erhalten. 'Den Bescheid empfangen.' Used in official correspondence. The word literally means 'to catch toward' (emp- + fangen)."},
{type:"mc",q:"Was bedeutet ausschließen?",opts:["to exclude","to contain","to include carefully","to receive"],ans:"to exclude",hint:"Aus- (out) + schließen (to close). To close something out."}
]},
{id:"deu_r19l5b",title:"Die Dokumentenprüfung (Teil 2)",icon:"\uD83D\uDD0D",xp:15,board:true,steps:[
{type:"intro",title:"Die Dokumentenprüfung (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"integrieren",src:"to integrate",pos:"verb",gender:null,note:"From Latin 'integrare' (to make whole).\n'Sich in die Gesellschaft integrieren.'",example:"A: Haben Sie sich gut integriert?\nB: Ja, ich habe Deutsch gelernt und arbeite hier.\nA: Das ist vorbildlich.\nB: Es war nicht immer einfach, aber es hat sich gelohnt.",exampleSrc:"A: Have you integrated well?\nB: Yes, I learned German and work here.\nA: That is exemplary.\nB: It wasn't always easy, but it was worth it.",funFact:"Germany expects active integration: language courses, civic knowledge, cultural participation. 'Sich in die Gesellschaft integrieren' is the official phrase."},
{type:"teach",trg:"illegal",src:"illegal",pos:"adj",gender:null,note:"Same in English. Il- (not) + legal. 'Illegaler Aufenthalt.'\nThe term 'irregulärer Aufenthalt' is increasingly preferred.",example:"A: Ist es illegal, ohne Visum zu arbeiten?\nB: Ja, das ist illegal.\nA: Was passiert dann?\nB: Es gibt hohe Strafen und Konsequenzen für den Aufenthalt.",exampleSrc:"A: Is it illegal to work without a visa?\nB: Yes, that is illegal.\nA: What happens then?\nB: There are heavy penalties and consequences for the residence status.",funFact:"'Illegaler Aufenthalt' = illegal stay. In German legal language, the term 'irregulärer Aufenthalt' is increasingly preferred. Both are used in official contexts."},
{type:"teach",trg:"recht",src:"right, correct (adjective)",pos:"adj",gender:null,note:"As adjective: right, correct. 'Das ist recht.'\nDifferent from 'Recht' (noun) and 'rechts' (to the right).",example:"A: Ist das so recht?\nB: Ja, das ist genau recht.\nA: Haben Sie recht verstanden?\nB: Ich glaube, ich habe alles recht gemacht.",exampleSrc:"A: Is that correct like this?\nB: Yes, that is exactly right.\nA: Did you understand correctly?\nB: I believe I did everything correctly.",funFact:"Three forms, three meanings: 'recht' (adjective: correct), 'Recht' (noun: law/right), 'rechts' (adverb: to the right). Context determines which meaning applies."},
{type:"teach",trg:"zugänglich",src:"accessible",pos:"adj",gender:null,note:"Zu- (to) + Gang (way) + -lich. Available, accessible.\n'Die Informationen sind öffentlich zugänglich.'",example:"A: Sind die Formulare online zugänglich?\nB: Ja, alle Formulare sind online zugänglich.\nA: Gut, dann kann ich mich vorbereiten.\nB: Die Website der Behörde ist sehr zugänglich.",exampleSrc:"A: Are the forms accessible online?\nB: Yes, all forms are accessible online.\nA: Good, then I can prepare.\nB: The authority's website is very accessible.",funFact:"Related to Zugang (access). In bureaucracy: services should be zugänglich for everyone. 'Die Informationen sind öffentlich zugänglich' = the information is publicly accessible."},
{type:"mc",q:"Die Beamtin sagt: 'Die Geburtsurkunde muss beglaubigt werden.' Was bedeutet das?",opts:["Das Dokument braucht eine offizielle Bestätigung.","Das Dokument muss komplett neu geschrieben werden.","Das Dokument ist falsch.","Das Dokument wird leider nicht akzeptiert."],ans:"Das Dokument braucht eine offizielle Bestätigung.",hint:"Beglaubigt means certified/authenticated. Muss...werden means it must be done."},
{type:"teach",trg:"nachdem",src:"after (conjunction)",pos:"conj",gender:null,note:"Temporal conjunction. The nachdem-clause uses Perfekt,\nthe main clause uses Präteritum or Präsens.",example:"A: Nachdem ich den Antrag abgegeben habe, warte ich.\nB: Wie lange dauert es?\nA: Nachdem alle Unterlagen geprüft sind, kommt die Antwort.\nB: Das kann Wochen dauern.",exampleSrc:"A: After I submitted the application, I wait.\nB: How long does it take?\nA: After all documents are checked, the answer comes.\nB: That can take weeks.",funFact:"Nachdem forces a time-sequence shift: the nachdem-clause is one tense further back than the main clause. Perfekt in nachdem, Präsens in main. Plusquamperfekt in nachdem, Präteritum in main."},
{type:"fb",s:"Der Antrag kann erst bearbeitet werden, {1} alle Unterlagen vollständig sind.",a:["nachdem"],opts:["nachdem","trotzdem","obwohl","falls"],hint:"Which conjunction means 'after'? The application can only be processed after everything is complete.",sSrc:"The application can only be processed after all documents are complete."},
{type:"mc",q:"Welcher Satz kombiniert falls mit Passiv + Modalverb richtig?",opts:["Falls ein Dokument fehlt, muss es später nachgereicht werden.","Falls ein Dokument fehlt, muss es nachgereicht werden.","Falls ein Dokument fehlt, es muss nachgereicht werden.","Ein Dokument fehlt, falls muss es nachgereicht werden."],ans:"Falls ein Dokument fehlt, muss es nachgereicht werden.",hint:"The conditional clause sends its verb to the end. After the comma, the main clause uses standard V2 word order."},
{type:"drag_fill",s:"Die Beamtin sagt, {1} der Antrag erst genehmigt werden {2}, {3} alle Gebühren bezahlt sind.",blanks:{"1":"dass","2":"kann","3":"nachdem"},pool:["dass","kann","nachdem","weil","muss","bevor"],hint:"First blank: the reporting connector after 'sagt'. Second blank: the modal pushed to the end of that clause. Third blank: the time connector for the fee condition.",sSrc:"The officer says that the application can only be approved after all fees are paid."},
{type:"mc",q:"Verumius fragt: 'Kann der Aufenthaltstitel auch vorläufig ausgestellt werden, falls die Beglaubigung noch fehlt?' Was will er?",opts:["Die Absage seines Antrags","Einen neuen Termin beim Konsulat","Eine temporäre Lösung, während ein Dokument noch fehlt","Einen endgültigen und unbefristeten Aufenthaltstitel sofort"],ans:"Eine temporäre Lösung, während ein Dokument noch fehlt",hint:"He uses the word meaning not yet final and a conjunction for an uncertain condition. He is asking for something provisional."},
{type:"mc",q:"Was bedeutet 'integrieren'?",opts:["after (conjunction)","the civil servant (female)","to exclude, to rule out","to integrate"],ans:"to integrate",hint:"Sounds like its English equivalent. Latin root: integrare (to make whole)."},
{type:"fb",s:"Ist es {1}, ohne Visum zu arbeiten?",a:["illegal"],opts:["der Einwohner","das Lager","nachdem","illegal"],hint:"Same word in English and German. Against the Gesetz.",sSrc:"Is it illegal to work without a visa?"},
{type:"mc",q:"Was bedeutet 'zugänglich'?",opts:["accessible","the embassy, the message","the pregnancy","to exclude, to rule out"],ans:"accessible",hint:"From Zugang (access) + -lich. Reachable and open to everyone."}
]},

// ===== LESSON 6: "Bankdeutsch und Briefpost" (Banking German and Postal Mail) =====
// Vocab teach (banking + mail + family). 18 new words. 24 steps.
{id:"deu_r19l6",title:"Bankdeutsch und Briefpost",icon:"\uD83C\uDFE6",xp:15,board:true,steps:[
{type:"intro",title:"Bankdeutsch und Briefpost",desc:"Money and mail: two pillars of German daily life. Cash, bank transfers, mailboxes, and registered letters. Plus: family words for official forms.",goals:["Learn banking and postal vocabulary","Describe family relationships","Master compound nouns for financial and postal services"]},
{type:"teach",trg:"das Bargeld",src:"the cash",pos:"noun",gender:"n",note:"Bar (cash/bare) + Geld (money). Cash money.\nGermany is one of the most cash-loving countries in Europe.",example:"A: Kann ich mit Karte bezahlen?\nB: Nein, wir nehmen nur Bargeld.\nA: Wo ist der nächste Geldautomat?\nB: Gleich um die Ecke.",exampleSrc:"A: Can I pay by card?\nB: No, we only accept cash.\nA: Where is the nearest ATM?\nB: Right around the corner.",funFact:"Germany is one of the most cash-loving countries in Europe. Many shops still do not accept cards. 'Bargeld abheben' = to withdraw cash. The word combines 'bar' (cash) + 'Geld' (money)."},
{type:"teach",trg:"das Girokonto",src:"the checking account",pos:"noun",gender:"n",note:"Giro (from Italian 'giro,' circulation) + Konto (account).\nEvery resident needs one. No Girokonto = no rent, no salary.",example:"A: Haben Sie ein Girokonto in Deutschland?\nB: Ja, bei der Sparkasse.\nA: Gut, ohne Girokonto geht nichts.\nB: Das habe ich schnell gelernt.",exampleSrc:"A: Do you have a checking account in Germany?\nB: Yes, at the savings bank.\nA: Good, nothing works without a checking account.\nB: I learned that quickly.",funFact:"Every resident needs a Girokonto. Without it: no rent payment, no salary, no insurance. The Anmeldung enables the Girokonto. The word comes from Italian 'giro' (circulation)."},
{type:"teach",trg:"die Überweisung",src:"the bank transfer",pos:"noun",gender:"f",note:"Über (over) + Weisung (direction). Germans pay rent, bills,\nand each other by Überweisung. IBAN is essential.",example:"A: Wie bezahle ich die Miete?\nB: Per Überweisung.\nA: Brauche ich dafür die IBAN?\nB: Ja, die IBAN des Vermieters.",exampleSrc:"A: How do I pay the rent?\nB: By bank transfer.\nA: Do I need the IBAN for that?\nB: Yes, the landlord's IBAN.",funFact:"Germans pay rent, bills, and each other by Überweisung. 'Können Sie mir die IBAN für die Überweisung geben?' is everyday banking German."},
{type:"teach",trg:"die Einzahlung",src:"the deposit",pos:"noun",gender:"f",note:"Ein- (in) + Zahlung (payment). A deposit into an account.\nOpposite: Auszahlung (withdrawal). Ein = in, Aus = out.",example:"A: Ich möchte eine Einzahlung machen.\nB: Wie viel möchten Sie einzahlen?\nA: 500 Euro.\nB: In bar oder per Überweisung?",exampleSrc:"A: I would like to make a deposit.\nB: How much would you like to deposit?\nA: 500 euros.\nB: In cash or by transfer?",funFact:"The opposite of Einzahlung is Auszahlung (withdrawal). Ein = in, Aus = out. Simple German logic for banking transactions."},
{type:"mc",q:"Wie bezahlen Deutsche normalerweise ihre Miete?",opts:["Per Überweisung","Per EC-Karte","Per Einschreiben","Per Bargeld"],ans:"Per Überweisung",hint:"Germans pay rent through a specific banking method that transfers money electronically."},
{type:"teach",trg:"abmachen",src:"to arrange, to agree on",pos:"verb",gender:null,note:"Separable: ab + machen. 'Wir haben einen Termin abgemacht.'\nAlso: etwas abmachen = to take something off.",example:"A: Wir hatten doch abgemacht, dass alle Originale dabei sein müssen.\nB: Tut mir leid, ich habe es vergessen.\nA: Bitte machen Sie einen neuen Termin ab.\nB: Ja, ich rufe morgen an.",exampleSrc:"A: We had agreed that all originals must be included.\nB: I am sorry, I forgot.\nA: Please arrange a new appointment.\nB: Yes, I will call tomorrow.",funFact:"Abmachen has two meanings: to agree/arrange (einen Termin abmachen) and to remove (ein Etikett abmachen). Context makes the meaning clear. Abgemacht! means Deal! or Agreed!"},
{type:"teach",trg:"der Beleg",src:"the receipt, the proof",pos:"noun",gender:"m",note:"From belegen (to prove/document).\nKassenbeleg = receipt. Beleg vorlegen = to present proof.",example:"A: Haben Sie den Beleg?\nB: Ja, hier ist der Kassenbeleg.\nA: Bitte heben Sie alle Belege auf.\nB: Für die Steuererklärung?",exampleSrc:"A: Do you have the receipt?\nB: Yes, here is the receipt.\nA: Please keep all receipts.\nB: For the tax return?",funFact:"Germans keep Belege for everything. Kassenbeleg (cash register receipt), Überweisungsbeleg (transfer receipt). Ohne Beleg kein Beweis (without receipt, no proof) is a German tax motto."},
{type:"teach",trg:"die EC-Karte",src:"the debit card",pos:"noun",gender:"f",note:"EC = Electronic Cash. The standard German debit card.\nNow officially called girocard, but everyone says EC-Karte.",example:"A: Kann ich mit EC-Karte bezahlen?\nB: Ja, ab fünf Euro.\nA: Wo ist meine EC-Karte?\nB: Vielleicht im Geldbeutel?",exampleSrc:"A: Can I pay with a debit card?\nB: Yes, from five euros.\nA: Where is my debit card?\nB: Maybe in the wallet?",funFact:"The EC-Karte was renamed girocard in 2007, but nobody uses the new name. Kreditkarte (credit card) is less common in Germany. Cash and EC-Karte dominate daily payments."},
{type:"teach",trg:"einzahlen",src:"to deposit (money)",pos:"verb",gender:null,note:"Separable: ein + zahlen. Opposite: abheben (to withdraw).\nGeld einzahlen = to deposit money.",example:"A: Ich möchte 200 Euro einzahlen.\nB: In bar oder per Überweisung?\nA: In bar, bitte.\nB: Bitte legen Sie das Geld in den Automaten.",exampleSrc:"A: I would like to deposit 200 euros.\nB: In cash or by transfer?\nA: In cash, please.\nB: Please put the money in the machine.",funFact:"Ein (in) + zahlen (to pay). Money goes IN. The opposite is abheben (to lift off/withdraw). Simple German logic: ein = in, ab = off/away."},
{type:"fb",s:"Bitte heben Sie den {1} auf. Sie brauchen ihn für die Steuererklärung.",a:["Beleg"],opts:["Beleg","Betrag","Zins","Kauf"],hint:"Which word means a receipt or proof of a transaction?",sSrc:"Please keep the receipt. You need it for the tax return."},
{type:"teach",trg:"der Betrag",src:"the amount (of money)",pos:"noun",gender:"m",note:"From 'betragen' (to amount to). 'Der Betrag beträgt 35 Euro.'\nYes, Betrag and betragen look almost the same.",example:"A: Welchen Betrag möchten Sie überweisen?\nB: Den Betrag von 100 Euro.\nA: Der Betrag wurde überwiesen.\nB: Danke, ich sehe die Bestätigung.",exampleSrc:"A: What amount would you like to transfer?\nB: The amount of 100 euros.\nA: The amount has been transferred.\nB: Thanks, I can see the confirmation.",funFact:"'Der Betrag beträgt 35 Euro.' Yes, Betrag (noun: amount) and betragen (verb: to amount to) look almost the same. The noun is the amount, the verb means 'to amount to.'"},
{type:"teach",trg:"der Zins",src:"the interest (financial)",pos:"noun",gender:"m",note:"From Latin 'census' (tax). Die Zinsen (plural) = interest rates.\n'Wie hoch sind die Zinsen?'",example:"A: Wie hoch sind die Zinsen auf dem Girokonto?\nB: Die Zinsen sind momentan sehr niedrig.\nA: Fast null Prozent?\nB: Ja, die Zinsen waren jahrelang negativ.",exampleSrc:"A: How high are the interest rates on the checking account?\nB: The interest rates are currently very low.\nA: Almost zero percent?\nB: Yes, interest rates were negative for years.",funFact:"Germany had negative Zinsen for years. The concept is central to Girokonto discussions. Die Zinsen (plural) = interest rates. The word comes from Latin 'census' (tax)."},
{type:"teach",trg:"der Geldautomat",src:"the ATM",pos:"noun",gender:"m",note:"Geld (money) + Automat (machine). ATM.\nAustria says Bankomat, Switzerland says Bancomat.",example:"A: Wo ist der nächste Geldautomat?\nB: Gegenüber, bei der Sparkasse.\nA: Kann ich dort auch Geld einzahlen?\nB: Ja, an diesem Geldautomaten geht beides.",exampleSrc:"A: Where is the nearest ATM?\nB: Across the street, at the savings bank.\nA: Can I also deposit money there?\nB: Yes, this ATM handles both.",funFact:"Austria says Bankomat, Switzerland says Bancomat, Germany says Geldautomat. Three countries, three words, one machine. The gender comes from 'der Automat.'"},
{type:"teach",trg:"die Bankleitzahl",src:"the bank routing number",pos:"noun",gender:"f",note:"Bank + Leit- (routing) + Zahl (number). Being replaced by IBAN.\nOlder forms still ask for it.",example:"A: Was ist Ihre Bankleitzahl?\nB: 10050000. Aber heute benutzt man die IBAN.\nA: Stimmt, die IBAN ist international.\nB: Die Bankleitzahl ist nur noch für alte Formulare.",exampleSrc:"A: What is your bank routing number?\nB: 10050000. But today we use the IBAN.\nA: True, the IBAN is international.\nB: The routing number is only for old forms.",funFact:"Being replaced by IBAN in Europe, but older forms still ask for it. The gender comes from the last element: die Zahl. This is the rule for all German compound nouns."},
{type:"mc",q:"Der Betrag beträgt 150 Euro. Was ist ein Betrag?",opts:["Ein Zinssatz","Eine Geldsumme","Eine Bankverbindung","Eine Gebühr"],ans:"Eine Geldsumme",hint:"Der Betrag refers to a specific amount of money in a transaction."}
]},
{id:"deu_r19l6b",title:"Bankdeutsch und Briefpost (Teil 2)",icon:"\uD83C\uDFE6",xp:15,board:true,steps:[
{type:"intro",title:"Bankdeutsch und Briefpost (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"der Briefkasten",src:"the mailbox",pos:"noun",gender:"m",note:"COMPOUND: Brief (letter) + Kasten (box).\nBrief (letter) + Kasten (box). Yellow in Germany (Deutsche Post).\nLeerungszeiten (collection times) posted on front.",example:"A: Wo ist der nächste Briefkasten?\nB: Am Ende der Straße, der gelbe Kasten.\nA: Wann wird er geleert?\nB: Jeden Tag um 17 Uhr.",exampleSrc:"A: Where is the nearest mailbox?\nB: At the end of the street, the yellow box.\nA: When is it emptied?\nB: Every day at 5 PM.",funFact:"Yellow in Germany (Deutsche Post). Every German neighborhood has one. Leerungszeiten (collection times) are posted on the front. Brief (letter) + Kasten (box) = mailbox."},
{type:"teach",trg:"der Briefumschlag",src:"the envelope",pos:"noun",gender:"m",note:"Brief (letter) + Umschlag (envelope, literally 'turn-around').\nGerman has precise postal vocabulary.",example:"A: Haben Sie einen Briefumschlag?\nB: Ja, hier. Welche Größe brauchen Sie?\nA: Einen großen Briefumschlag für die Unterlagen.\nB: A4? Hier, bitte.",exampleSrc:"A: Do you have an envelope?\nB: Yes, here. What size do you need?\nA: A large envelope for the documents.\nB: A4? Here you go.",funFact:"'Umschlag' literally means 'turn-around,' because you fold paper around the letter. German has some of the most precise postal vocabulary of any language."},
{type:"teach",trg:"der Briefträger",src:"the mail carrier (male)",pos:"noun",gender:"m",note:"Brief (letter) + Träger (carrier). Die Briefträgerin = female.\nGerman mail delivery is remarkably punctual.",example:"A: Wann kommt der Briefträger?\nB: Jeden Tag gegen zehn Uhr.\nA: Auch am Samstag?\nB: Ja, aber nicht am Sonntag.",exampleSrc:"A: When does the mail carrier come?\nB: Every day around ten o'clock.\nA: Also on Saturday?\nB: Yes, but not on Sunday.",funFact:"In Germany, mail delivery is remarkably punctual. You can almost set your clock by the Briefträger. Der Briefträger, die Briefträgerin. Brief (letter) + Träger (carrier)."},
{type:"teach",trg:"das Einschreiben",src:"the registered mail",pos:"noun",gender:"n",note:"Ein- (in) + schreiben (to write). Registered mail with proof.\n'Per Einschreiben schicken' for important documents.",example:"A: Wie soll ich den Antrag schicken?\nB: Per Einschreiben.\nA: Warum per Einschreiben?\nB: Weil Sie dann einen Beweis haben, dass es angekommen ist.",exampleSrc:"A: How should I send the application?\nB: By registered mail.\nA: Why by registered mail?\nB: Because then you have proof that it arrived.",funFact:"For anything important (Kündigung, Antrag, Beschwerde), Germans use Einschreiben. Proof of delivery. 'Per Einschreiben schicken' is the safest way to send official documents."},
{type:"fb",s:"Der gelbe Kasten an der Straße ist ein {1}.",a:["Briefkasten"],opts:["Briefkasten","Briefumschlag","Briefträger","Einschreiben"],hint:"Which compound noun combines letter + box?",sSrc:"The yellow box on the street is a mailbox."},
{type:"teach",trg:"der Cousin",src:"the cousin (male)",pos:"noun",gender:"m",note:"From French. Pronounced koo-ZAN. Die Cousine = female.\nGerman borrowed these because Vetter/Base became outdated.",example:"A: Hast du Verwandte in Deutschland?\nB: Ja, mein Cousin lebt in München.\nA: Und deine Cousine?\nB: Sie lebt in Hamburg.",exampleSrc:"A: Do you have relatives in Germany?\nB: Yes, my cousin lives in Munich.\nA: And your female cousin?\nB: She lives in Hamburg.",funFact:"Pronounced the French way in German: koo-ZAN (Cousin), koo-ZEE-neh (Cousine). German borrowed these because the old Germanic words (Vetter/Base) became outdated."},
{type:"teach",trg:"der Neffe",src:"the nephew",pos:"noun",gender:"m",note:"From Latin 'nepos' (grandson, then nephew). Your sibling's son.\nSame root as English 'nephew' and 'nepotism.'",example:"A: Wer ist der Junge?\nB: Das ist mein Neffe, der Sohn meiner Schwester.\nA: Und das Mädchen?\nB: Das ist meine Nichte.",exampleSrc:"A: Who is the boy?\nB: That's my nephew, my sister's son.\nA: And the girl?\nB: That's my niece.",funFact:"Same root as English 'nephew' and the word 'nepotism' (favoring your nephews). From Latin 'nepos' (grandson, then nephew)."},
{type:"teach",trg:"die Nichte",src:"the niece",pos:"noun",gender:"f",note:"Your sibling's daughter. Die Nichte.\nNot related to 'nicht' (not), despite the similar spelling.",example:"A: Ist das deine Nichte?\nB: Ja, die Tochter meines Bruders.\nA: Sie sieht dir ähnlich.\nB: Das sagen alle.",exampleSrc:"A: Is that your niece?\nB: Yes, my brother's daughter.\nA: She looks like you.\nB: Everyone says that.",funFact:"Not related to 'nicht' (not), despite the similar appearance. Die Nichte is your sibling's daughter. The word has its own Latin etymology."},
{type:"teach",trg:"der Onkel",src:"the uncle",pos:"noun",gender:"m",note:"From French 'oncle,' from Latin 'avunculus.'\nAlso used affectionately: 'Onkel' + first name for close friends.",example:"A: Mein Onkel kommt zu Besuch.\nB: Aus Deutschland?\nA: Nein, aus Griechenland.\nB: Schön, dass er dich besucht.",exampleSrc:"A: My uncle is coming to visit.\nB: From Germany?\nA: No, from Greece.\nB: Nice that he's visiting you.",funFact:"Every German child calls friendly adult men 'Onkel' even if they are not related. 'Onkel' + first name = affectionate address. From French 'oncle,' from Latin 'avunculus.'"},
{type:"tip",title:"Zusammengesetzte Nomen im Bankwesen",text:"German builds banking vocabulary by combining words into compounds:\n\n- Geld and Automat become Geldautomat (ATM)\n- Bank, Leit, and Zahl become Bankleitzahl (bank routing number)\n- Über and Weisung become Überweisung (bank transfer)\n\nThe gender always comes from the LAST element:\n- der Automat is masculine, so der Geldautomat is also masculine.\n- die Zahl is feminine, so die Bankleitzahl is also feminine.\n- die Weisung is feminine, so die Überweisung is also feminine.\n\nMaster this rule and you can decode any compound noun.\n\nBonus: der Beleg (receipt). After every Einzahlung or Überweisung,\nyou get a Beleg as proof. Der Beleg ist Ihre Bestätigung.",deepDive:"This rule is universal in German. No exceptions. Die Tasche is feminine, so die Brieftasche is also feminine. Der Kasten is masculine, so der Briefkasten is also masculine. Das Konto is neuter, so das Girokonto is also neuter. The last word always determines the gender."},
{type:"mc",q:"Verumius möchte Geld abheben. Wo geht er hin?",opts:["Zum Geldautomaten","Zur Einzahlung","Zur Überweisung","Zum Briefkasten"],ans:"Zum Geldautomaten",hint:"Abheben means to withdraw. Which machine gives you Bargeld?"},
{type:"match",pairs:[{trg:"Girokonto",src:"checking account"},{trg:"Überweisung",src:"bank transfer"},{trg:"Bargeld",src:"cash"},{trg:"Einzahlung",src:"deposit"},{trg:"Geldautomat",src:"ATM"}]},
{type:"teach",trg:"ausführen",src:"to execute / to carry out",pos:"verb",gender:null,note:"Separable: führt aus. Past: ausgeführt. Formal; used for orders, transfers, tasks.",example:"A: Wann wird die Überweisung ausgeführt?\nB: Innerhalb von drei Tagen.\nA: Und wenn es länger dauert?\nB: Dann können Sie reklamieren.",exampleSrc:"A: When will the transfer be executed?\nB: Within three days.\nA: And if it takes longer?\nB: Then you can lodge a complaint.",funFact:"'Ausführen' literally means 'to lead out' (aus = out, führen = to lead). In banking it means executing a transfer. The same verb is also used for walking a dog: 'den Hund ausführen.'"},
{type:"drag_fill",s:"Die Überweisung {1} innerhalb von drei Tagen {2} {3}.",blanks:{"1":"muss","2":"ausgeführt","3":"werden"},pool:["muss","ausgeführt","werden","kann","ausführen","wird"],hint:"Three blanks: the obligation modal, then the past participle of 'ausführen', then the passive auxiliary at the end.",sSrc:"The transfer must be executed within three days."},
{type:"mc",q:"Was bedeutet 'der Cousin'?",opts:["the cash","the cousin (male)","to execute / to carry out","to deposit (money)"],ans:"the cousin (male)",hint:"French loanword, same spelling. A relative of your generation born to an aunt or uncle."},
{type:"fb",s:"Wie sagt man 'the nephew' auf Deutsch? {1}",a:["der Neffe"],opts:["der Neffe","der Onkel","der Briefkasten","der Cousin"],hint:"Your sibling's son. Related to English 'nephew.'",sSrc:"How do you say 'the nephew' in German?"},
{type:"mc",q:"Was bedeutet 'der Onkel'?",opts:["to arrange, to agree on","the envelope","the uncle","the bank transfer"],ans:"the uncle",hint:"French loanword. Your parent's brother or aunt's husband."}
]},

// ===== LESSON 7: "Alles auf dem Prüfstand" (Everything Under Review) =====
// Comprehensive quiz. 10 new words. 22 steps.
{id:"deu_r19l7",title:"Alles auf dem Prüfstand",icon:"\u2705",xp:15,board:true,steps:[
{type:"intro",title:"Alles auf dem Prüfstand",desc:"Everything from Unit 19 under review. Passive with modal verbs, conjunctions, bureaucracy, banking, family. Show what you can do.",goals:["Test passive with modal verbs and conjunctions","Prove your government office and banking vocabulary","Combine multiple grammar structures in complex sentences"]},


{type:"teach",trg:"der Enkel",src:"the grandson, the grandchild",pos:"noun",gender:"m",note:"From Old High German 'eninchili' (little grandfather).\nDie Enkelin = granddaughter. Originally 'little ancestor.'",example:"A: Haben Sie Enkel?\nB: Ja, zwei Enkel und eine Enkelin.\nA: Wie alt sind sie?\nB: Der Enkel ist fünf, die Enkelin ist drei.",exampleSrc:"A: Do you have grandchildren?\nB: Yes, two grandsons and one granddaughter.\nA: How old are they?\nB: The grandson is five, the granddaughter is three.",funFact:"The word originally meant 'little ancestor' because grandchildren resemble grandparents. Der Enkel (grandson), die Enkelin (granddaughter). From Old High German 'eninchili.'"},

{type:"teach",trg:"die Angehörige",src:"the relative, the family member",pos:"noun",gender:"f",note:"An- (to) + gehören (to belong) + -ige. Family member.\n'Nächste Angehörige' = next of kin on official forms.",example:"A: Wer sind Ihre nächsten Angehörigen?\nB: Meine Schwester und mein Onkel.\nA: Name und Rufnummer bitte.\nB: Maria, 0170-1234567.",exampleSrc:"A: Who are your next of kin?\nB: My sister and my uncle.\nA: Name and phone number please.\nB: Maria, 0170-1234567.",funFact:"'Nächste Angehörige' = next of kin. On official forms, this field asks who should be contacted in emergencies. The word means 'those who belong to you.'"},

{type:"teach",trg:"verwandt",src:"related (by family)",pos:"adj",gender:null,note:"'Wir sind verwandt' = We are related.\nDie Verwandtschaft = the relatives (collectively).",example:"A: Sind Sie mit Herrn Müller verwandt?\nB: Ja, er ist mein Onkel.\nA: Haben Sie noch mehr Verwandte in Berlin?\nB: Ja, die ganze Verwandtschaft lebt hier.",exampleSrc:"A: Are you related to Mr. Müller?\nB: Yes, he is my uncle.\nA: Do you have more relatives in Berlin?\nB: Yes, the whole family lives here.",funFact:"Germans take Verwandtschaft seriously at holidays. Die Verwandtschaft = the relatives (collectively). 'Wir sind verwandt' = we are related."},

{type:"teach",trg:"spätestens",src:"at the latest",pos:"adv",gender:null,note:"Superlative of 'spät' (late) + -ens. Absolute deadline.\n'Spätestens am Freitag' = by Friday at the latest.",example:"A: Wann muss der Antrag eingereicht sein?\nB: Spätestens am 15. März.\nA: Und wenn ich zu spät bin?\nB: Dann wird der Antrag nicht mehr bearbeitet.",exampleSrc:"A: When must the application be submitted?\nB: By March 15th at the latest.\nA: And if I'm too late?\nB: Then the application will no longer be processed.",funFact:"The word bureaucrats use to set absolute deadlines. No flexibility after spätestens. 'Spätestens am Freitag' means there is absolutely no extension beyond Friday."},

{type:"teach",trg:"ausschließlich",src:"exclusively",pos:"adv",gender:null,note:"Aus- + schließlich (finally). Only this, nothing else.\n'Ausschließlich mit Termin' = by appointment only.",example:"A: Kann ich ohne Termin kommen?\nB: Nein, ausschließlich mit Termin.\nA: Und online?\nB: Der Service ist ausschließlich persönlich.",exampleSrc:"A: Can I come without an appointment?\nB: No, by appointment only.\nA: And online?\nB: The service is exclusively in person.",funFact:"The Behörde loves this word. It means 'only this, nothing else.' 'Ausschließlich mit Termin' = by appointment only. No exceptions."},

{type:"mc",q:"Die Tochter deines Sohnes ist deine...?",opts:["Enkelin","Schwiegertochter","Nichte","Tante"],ans:"Enkelin",hint:"Your grandchild through your son. One generation below your child."},

{type:"teach",trg:"statt",src:"instead of",pos:"prep",gender:null,note:"Short for 'anstatt.' Preposition with genitive.\n'Statt einer Kopie brauchen wir das Original.'",example:"A: Kann ich eine Kopie bringen?\nB: Nein, statt einer Kopie brauchen wir das Original.\nA: Statt einer Überweisung kann ich bar bezahlen?\nB: Ja, das geht auch.",exampleSrc:"A: Can I bring a copy?\nB: No, instead of a copy we need the original.\nA: Instead of a transfer, can I pay cash?\nB: Yes, that works too.",funFact:"Short for 'anstatt' (instead of). Takes genitive. 'Statt einer Kopie brauchen wir das Original.' Also used in 'statt...zu' (instead of doing)."},

{type:"teach",trg:"trotz",src:"despite",pos:"prep",gender:null,note:"Preposition with genitive. 'Trotz aller Schwierigkeiten.'\nRelated to trotzdem (adverb: nevertheless).",example:"A: Trotz aller Schwierigkeiten hat er den Antrag eingereicht.\nB: Das war mutig.\nA: Trotz der langen Wartezeit blieb er geduldig.\nB: Beeindruckend.",exampleSrc:"A: Despite all difficulties, he submitted the application.\nB: That was brave.\nA: Despite the long wait, he remained patient.\nB: Impressive.",funFact:"Closely related to trotzdem (nevertheless). Trotz = preposition with genitive, trotzdem = adverb. 'Trotz aller Schwierigkeiten' = despite all difficulties."},

{type:"teach",trg:"dahin",src:"there, to that place",pos:"adv",gender:null,note:"Da- (there) + hin (toward). Direction away from the speaker.\nContrast: daher = from there (toward speaker).",example:"A: Wie komme ich zur Ausländerbehörde?\nB: Fahren Sie mit der U-Bahn. Linie 6 fährt dahin.\nA: Wie lange brauche ich dahin?\nB: Etwa 20 Minuten.",exampleSrc:"A: How do I get to the immigration office?\nB: Take the subway. Line 6 goes there.\nA: How long does it take to get there?\nB: About 20 minutes.",funFact:"Hin and her define direction in German. Dahin = there (away from speaker). Daher = from there (toward speaker). 'Wie komme ich dahin?' = How do I get there?"},

{type:"teach",trg:"die Tante",src:"the aunt",pos:"noun",gender:"f",note:"From French 'tante.' Your parent's sister.\n'Tante-Emma-Laden' = a small corner shop.",example:"A: Meine Tante kommt morgen zu Besuch.\nB: Aus welcher Stadt?\nA: Aus Düsseldorf.\nB: Schön, dann habt ihr Familienbesuch.",exampleSrc:"A: My aunt is coming to visit tomorrow.\nB: From which city?\nA: From Düsseldorf.\nB: Nice, then you'll have family visiting.",funFact:"'Tante-Emma-Laden' is a German expression for a small corner shop (Aunt Emma's shop). Die Tante is the counterpart to der Onkel. Also used affectionately for older family friends."},

{type:"teach",trg:"die Enkelin",src:"the granddaughter",pos:"noun",gender:"f",note:"Enkel + -in. The feminine form of Enkel.\nPlural: die Enkelinnen.",example:"A: Ist das Ihre Enkelin?\nB: Ja, sie heißt Lena.\nA: Wie alt ist Ihre Enkelin?\nB: Drei Jahre alt.",exampleSrc:"A: Is that your granddaughter?\nB: Yes, her name is Lena.\nA: How old is your granddaughter?\nB: Three years old.",funFact:"The feminine form of Enkel. Der Enkel (grandson/grandchild), die Enkelin (granddaughter). Plural: die Enkelinnen. German always provides gendered forms for family members."},

{type:"mc",q:"Der Aufenthaltstitel _____ beantragt werden.",opts:["hat","muss","ist","müsste"],ans:"muss",hint:"Which modal expresses obligation? Structure: modal + PP + werden."},

{type:"mc",q:"Ohne Visum _____ in Deutschland nicht gearbeitet _____.",opts:["sollte...gehabt haben","kann...sein","darf...werden","muss...werden"],ans:"darf...werden",hint:"Working without a visa is not just absent, it is forbidden. Which modal pair expresses prohibition in a passive construction?"},

{type:"fb",s:"{1} er alle Dokumente hatte, war er trotzdem nervös.",a:["Obwohl"],opts:["Obwohl","Trotzdem","Bevor","Weil"],hint:"Which conjunction means 'although'? It requires verb-final order.",sSrc:"Although he had all documents, he was still nervous."},

{type:"mc",q:"Verumius wartet, _____ seine Nummer aufgerufen wird.",opts:["seitdem","damit","falls","bis"],ans:"bis",hint:"He waits until a specific event happens. Which conjunction means 'until'?"},

{type:"fb",s:"Der Antrag kann erst genehmigt werden, {1} alle Gebühren bezahlt sind.",a:["nachdem"],opts:["nachdem","obwohl","falls","bevor"],hint:"The approval happens AFTER the fees are paid. Which conjunction marks time sequence?",sSrc:"The application can only be approved after all fees are paid."},

{type:"mc",q:"Welcher Satz kombiniert Bedingung mit Passiv + Modalverb richtig?",opts:["Falls die Frist abläuft, muss der Antrag neu gestellt werden.","Die Frist abläuft falls, muss der Antrag neu gestellt werden.","Falls die Frist abläuft, der Antrag muss neu gestellt werden.","Falls die Frist abläuft, muss der Antrag unbedingt neu und vollständig gestellt werden."],ans:"Falls die Frist abläuft, muss der Antrag neu gestellt werden.",hint:"The subordinate clause puts its conjugated form at the end. After the comma, V2 positioning applies, with the passive infinitive last."},

{type:"match",pairs:[{trg:"obwohl",src:"although"},{trg:"bevor",src:"before"},{trg:"seitdem",src:"since (time)"},{trg:"damit",src:"so that"},{trg:"falls",src:"in case"}]},

{type:"drag_fill",s:"{1} Verumius den Antrag eingereicht hat, {2} der Bescheid innerhalb von sechs Wochen {3} {4}.",blanks:{"1":"Nachdem","2":"muss","3":"ausgestellt","4":"werden"},pool:["Nachdem","muss","ausgestellt","werden","Bevor","kann","ausstellen","wird"],hint:"Four blanks: the time conjunction, the obligation modal, the past participle of 'ausstellen', then the passive auxiliary.",sSrc:"After Verumius submitted the application, the decision must be issued within six weeks."},

{type:"mc",q:"Was ist der Unterschied zwischen Wohnort und Wohnsitz?",opts:["Wohnort ist formeller als Wohnsitz","Wohnsitz ist die offizielle Meldeadresse","Wohnsitz bedeutet Arbeitsplatz","Es gibt praktisch keinen Unterschied zwischen den beiden"],ans:"Wohnsitz ist die offizielle Meldeadresse",hint:"One implies an officially recorded address. The other refers to a place more broadly."},

{type:"fb",s:"Die Tochter meines Bruders ist meine {1}.",a:["Nichte"],opts:["Nichte","Cousine","Enkelin","Tante"],hint:"Your brother's daughter is a specific family relationship. Which option names a sibling's female child?",sSrc:"My brother's daughter is my niece."},

{type:"mc",q:"Die Überweisung muss bis Freitag ausgeführt werden. Was bedeutet das?",opts:["Die Zinsen werden berechnet.","Man braucht Bargeld sofort.","Der Bankauftrag hat eine Frist bis Freitag.","Die Bank ist leider geschlossen und hat keinen Automaten."],ans:"Der Bankauftrag hat eine Frist bis Freitag.",hint:"The sentence expresses an obligation plus a time limit. Identify the type of constraint described."},

{type:"drag_fill",s:"{1} die Beamtin alle Unterlagen geprüft hat, {2} der Aufenthaltstitel {3} {4}, {5} alle Gebühren bezahlt sind.",blanks:{"1":"Nachdem","2":"kann","3":"ausgestellt","4":"werden","5":"falls"},pool:["Nachdem","kann","ausgestellt","werden","falls","Bevor","muss","ausstellen","wird","obwohl"],hint:"After the officer checked everything, the permit can be issued, if all fees are paid. Time + possibility + condition.",sSrc:"After the officer checked all documents, the residence permit can be issued, if all fees are paid."},

{type:"mc",q:"Verumius muss seinen Antrag bis Freitag einreichen. Welches Wort beschreibt diesen Zeitpunkt?",opts:["ausschließlich","vorläufig","dahin","spätestens"],ans:"spätestens",hint:"The word that marks an absolute deadline. Not one day later is acceptable."}
]},

// ===== LESSON 8: "Ich habe es geschafft!" (I Made It!) =====
// Story resolution + cultural deep dive. 13 new words. 22 steps.
{id:"deu_r19l8",title:"Ich habe es geschafft!",icon:"\uD83C\uDF89",xp:15,board:true,steps:[
{type:"intro",title:"Ich habe es geschafft!",desc:"The stamp falls. THUNK. Approved. Verumius calls KD. The group chat explodes. Official resident of Germany.",goals:["Celebrate Verumius' residence permit","Learn vocabulary for commerce and everyday life","Reflect on the bureaucratic journey and German administrative culture"]},
{type:"teach",trg:"der Käufer",src:"the buyer (male)",pos:"noun",gender:"m",note:"From 'kaufen' (to buy). Die Käuferin = female buyer.\nIn contracts: Käufer (buyer) vs. Verkäufer (seller).",example:"A: Wer ist der Käufer?\nB: Herr Schmidt ist der Käufer.\nA: Und die Käuferin?\nB: Frau Weber kauft das zweite Auto.",exampleSrc:"A: Who is the buyer?\nB: Mr. Schmidt is the buyer.\nA: And the female buyer?\nB: Mrs. Weber is buying the second car.",funFact:"In legal contracts, the Käufer is the buyer, the Verkäufer is the seller. Every Kaufvertrag (sales contract) names both. The word comes from 'kaufen' (to buy)."},
{type:"teach",trg:"die Verkäuferin",src:"the sales clerk (female)",pos:"noun",gender:"f",note:"Ver- + Käuferin. Female sales clerk. Der Verkäufer = male.\nCommon job title on signs: 'Verkäuferin gesucht.'",example:"A: Entschuldigung, können Sie mir helfen?\nB: Ja, ich bin die Verkäuferin. Was suchen Sie?\nA: Einen neuen Ordner für meine Dokumente.\nB: Die Ordner finden Sie in Gang drei.",exampleSrc:"A: Excuse me, can you help me?\nB: Yes, I'm the sales clerk. What are you looking for?\nA: A new folder for my documents.\nB: You'll find the folders in aisle three.",funFact:"In German, you still commonly see gendered job titles on signs: 'Verkäuferin gesucht' (female sales clerk wanted). The masculine form is Verkäufer."},
{type:"teach",trg:"die Betriebsrätin",src:"the works council member (female)",pos:"noun",gender:"f",note:"Betrieb (company) + Rat (council) + -in. Employee representative\nwith real legal power. Codetermination = Mitbestimmung.",example:"A: Wer ist die Betriebsrätin?\nB: Frau Schneider vertritt die Mitarbeiter.\nA: Was macht die Betriebsrätin genau?\nB: Sie verhandelt Arbeitsbedingungen mit der Geschäftsleitung.",exampleSrc:"A: Who is the works council member?\nB: Ms. Schneider represents the employees.\nA: What exactly does the works council member do?\nB: She negotiates working conditions with management.",funFact:"Der Betriebsrat is a uniquely German institution: employee representatives with real legal power. Codetermination (Mitbestimmung) is fundamental to German labor law."},
{type:"teach",trg:"die Chipkarte",src:"the chip card",pos:"noun",gender:"f",note:"Chip + Karte. A card with an electronic chip.\nDie EC-Karte is the German debit card (officially 'girocard').",example:"A: Haben Sie Ihre Chipkarte dabei?\nB: Ja, hier ist meine EC-Karte.\nA: Die EC-Karte ist auch eine Chipkarte.\nB: Stimmt, mit dem goldenen Chip.",exampleSrc:"A: Do you have your chip card with you?\nB: Yes, here is my debit card.\nA: The debit card is also a chip card.\nB: Right, with the golden chip.",funFact:"Die EC-Karte (Electronic Cash card) is the German debit card. Germans use 'EC-Karte' even though the official name changed to 'girocard' in 2007. Old habits die hard."},
{type:"fb",s:"In der Schweiz sagt man {1}, in Österreich Bankomat, in Deutschland Geldautomat.",a:["Bancomat"],opts:["Bancomat","Chipkarte","EC-Karte","Brieftasche"],hint:"Which word is the Swiss German term for ATM?",sSrc:"In Switzerland they say Bancomat, in Austria Bankomat, in Germany Geldautomat."}
]},
{id:"deu_r19l8b",title:"Ich habe es geschafft! (Teil 2)",icon:"\uD83C\uDF89",xp:15,board:true,steps:[
{type:"intro",title:"Ich habe es geschafft! (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"der Bancomat",src:"the ATM (Swiss German)",pos:"noun",gender:"m",note:"Swiss German for ATM. From Italian 'banco' (bank) +\n'automatico.' Die Bancomatkarte = Swiss debit card.",example:"A: Wo ist der nächste Bancomat?\nB: In der Schweiz sagt man Bancomat.\nA: Und in Deutschland?\nB: Da sagt man Geldautomat.",exampleSrc:"A: Where is the nearest ATM?\nB: In Switzerland they say Bancomat.\nA: And in Germany?\nB: There they say Geldautomat.",funFact:"Switzerland has its own banking vocabulary. Same machine, different name. Bancomat (Swiss) vs. Bankomat (Austrian) vs. Geldautomat (German)."},
{type:"teach",trg:"der Bankomat",src:"the ATM (Austrian German)",pos:"noun",gender:"m",note:"Austrian German for ATM. Die Bankomatkarte = Austrian\ndebit card. Three countries, three words, one machine.",example:"A: Ich suche einen Bankomaten.\nB: In Österreich sagt man Bankomat.\nA: Und die Karte heißt Bankomatkarte?\nB: Ja, genau.",exampleSrc:"A: I'm looking for an ATM.\nB: In Austria they say Bankomat.\nA: And the card is called Bankomatkarte?\nB: Yes, exactly.",funFact:"Austria says Bankomat, Switzerland says Bancomat, Germany says Geldautomat. Three countries, three words. Austrian German is its own world with many unique terms."},
{type:"teach",trg:"die Brieftasche",src:"the wallet",pos:"noun",gender:"f",note:"Brief (letter) + Tasche (bag). Originally for carrying letters.\nDas Portemonnaie (from French) is the elegant alternative.",example:"A: Wo ist meine Brieftasche?\nB: Auf dem Tisch, neben den Schlüsseln.\nA: Danke, ich brauche mein Portemonnaie für die Gebühr.\nB: Brieftasche und Portemonnaie sind dasselbe.",exampleSrc:"A: Where is my wallet?\nB: On the table, next to the keys.\nA: Thanks, I need my wallet for the fee.\nB: Brieftasche and Portemonnaie are the same thing.",funFact:"Brief (letter) + Tasche (bag) = wallet (originally for carrying letters/documents). Das Portemonnaie is from French 'porte-monnaie' (money carrier). Both mean wallet. Brieftasche is more German, Portemonnaie more elegant."},
{type:"teach",trg:"der Zuschlag",src:"the surcharge, the supplement",pos:"noun",gender:"m",note:"Zu- (to) + Schlag (strike/hit). Extra charge on top of base price.\nICE-Zuschlag, Nachtzuschlag.",example:"A: Gibt es einen Zuschlag für den ICE?\nB: Ja, der ICE-Zuschlag beträgt 13 Euro.\nA: Und für die erste Klasse?\nB: Da kommt noch ein Zuschlag dazu.",exampleSrc:"A: Is there a surcharge for the ICE?\nB: Yes, the ICE surcharge is 13 euros.\nA: And for first class?\nB: There's an additional surcharge for that.",funFact:"ICE-Zuschlag (high-speed train surcharge). Nachtzuschlag (night surcharge). Germany loves adding Zuschläge to base prices. Zu- (to) + Schlag (strike/hit)."},
{type:"tip",title:"Deutsche Bürokratie: Warum sie so funktioniert",text:"Germany's administrative system dates back to Prussian efficiency reforms in the 1700s.\n\nThe principle: if something is documented, it exists. If it is not documented, it does not.\n\nThis explains the obsession with Urkunden, Bescheinigungen, and Originale.\n\nThe Ausländerbehörde is not trying to be difficult. It follows a system designed for maximum legal certainty.\n\nEvery stamp, every Frist, every Bestätigung serves a purpose: protecting both the state and the individual.\n\n'Ordnung muss sein' (there must be order) captures the philosophy.",deepDive:"The German word 'Beamtenstaat' (civil servant state) describes a country where bureaucracy is a profession, not just a job. Beamte study for years, pass state exams, and receive lifelong employment. This creates consistency but also rigidity. The system prioritizes fairness through uniformity: everyone follows the same rules, fills out the same forms, waits the same amount of time."},
{type:"mc",q:"Nachdem alle Unterlagen geprüft worden waren, _____ der Aufenthaltstitel ausgestellt _____.",opts:["konnte...werden","sollte...geworden sein","musste...sein","wurde...haben"],ans:"konnte...werden",hint:"The checking is complete. The permit becomes possible to issue. Which modal expresses ability in the past, combined with a passive infinitive?"},
{type:"mc",q:"Verumius feiert, _____ er wochenlang auf den Termin gewartet hat.",opts:["stattdessen","nachdem","obwohl","damit"],ans:"nachdem",hint:"He celebrates after waiting. Which conjunction marks completed prior action?"},
{type:"fb",s:"In Deutschland muss jeder Einwohner einen {1} haben.",a:["Wohnsitz"],opts:["Wohnsitz","Arbeitsplatz","Aufenthaltstitel","Pass"],hint:"The official registered address that everyone needs. The Anmeldung establishes this.",sSrc:"In Germany, every resident must have a registered address."},
{type:"mc",q:"In Österreich sagt man 'Bankomat.' In der Schweiz sagt man...?",opts:["Chipkarte","Geldautomat","Bancomat","EC-Karte"],ans:"Bancomat",hint:"Swiss German borrows from Italian rather than English for this machine. The spelling differs from the Austrian term by a single letter."},
{type:"match",pairs:[{trg:"Behörde",src:"government authority"},{trg:"Aufenthalt",src:"residence/stay"},{trg:"Gebühr",src:"fee"},{trg:"Überweisung",src:"bank transfer"},{trg:"Einschreiben",src:"registered mail"}]},
{type:"drag_fill",s:"{1} Verumius alle Dokumente eingereicht hatte, {2} der Aufenthaltstitel genehmigt {3}, {4} er alle Gebühren bezahlt hatte.",blanks:{"1":"Nachdem","2":"konnte","3":"werden","4":"nachdem"},pool:["Nachdem","konnte","werden","nachdem","Bevor","wurde","wird","obwohl"],hint:"Four blanks: time conjunction, past-tense ability modal, passive auxiliary, then the same time conjunction again for the payment condition.",sSrc:"After Verumius had submitted all documents, the residence permit could be approved, after he had paid all fees."},
{type:"mc",q:"Was musste Verumius alles machen, bevor der Aufenthaltstitel genehmigt werden konnte?",opts:["Nur die Gebühr bezahlen und abwarten","Nichts, der Aufenthaltstitel wird automatisch ausgestellt ohne eigenes Zutun","Nur das Visum verlängern und nichts mehr","Alle Unterlagen sammeln, Gebühren bezahlen und rechtzeitig den Antrag stellen"],ans:"Alle Unterlagen sammeln, Gebühren bezahlen und rechtzeitig den Antrag stellen",hint:"The full process requires multiple steps. Which answer covers everything?"},
{type:"fb",s:"Der Aufenthaltstitel muss {1} am Schalter abgeholt werden.",a:["spätestens"],opts:["spätestens","ausschließlich","trotz","dahin"],hint:"Which adverb sets an absolute time limit, meaning no later than a certain date?",sSrc:"The residence permit must be picked up by the counter at the latest."},
{type:"mc",q:"Was bedeutet 'der Bankomat'?",opts:["the ATM (Austrian German)","the surcharge, the supplement","the sales clerk (female)","the buyer (male)"],ans:"the ATM (Austrian German)",hint:"Bank + Automat combined. Regional word for the machine that dispenses cash."},
{type:"fb",s:"Wie sagt man 'the surcharge, the supplement' auf Deutsch? {1}",a:["der Zuschlag"],opts:["der Zuschlag","die Chipkarte","die Brieftasche","die Verkäuferin"],hint:"Zu- (additional) + Schlag (hit/charge). An extra fee on top of the price.",sSrc:"How do you say 'the surcharge, the supplement' in German?"}
,{type:"match",pairs:[{trg:"sicher",src:"safe, certain, sure"},{trg:"die Meldung",src:"the registration, the report"},{trg:"die Herkunft",src:"the origin"},{trg:"die Integration",src:"the integration"},{trg:"die Migration",src:"the migration"},{trg:"der Migrant",src:"the migrant (male)"}]},{type:"match",pairs:[{trg:"verantwortlich",src:"responsible"},{trg:"genehmigen",src:"to approve, to grant permission"},{trg:"ausstellen",src:"to issue (a document)"},{trg:"anerkennen",src:"to officially recognize"},{trg:"erhalten",src:"to receive (formal)"},{trg:"enthalten",src:"to contain"}]},{type:"match",pairs:[{trg:"fällig",src:"due, payable"},{trg:"untersagt",src:"forbidden, prohibited"},{trg:"voraussichtlich",src:"presumably, expected"},{trg:"einschließlich",src:"including (formal)"},{trg:"abhängen",src:"to depend on"},{trg:"abstimmen",src:"to coordinate, to align"}]},{type:"match",pairs:[{trg:"umgehen",src:"to handle, to deal with"},{trg:"sichern",src:"to secure, to safeguard"},{trg:"der Zugang",src:"the access"},{trg:"der Zivilstand",src:"the marital status"},{trg:"ablaufen",src:"to expire / to run out"},{trg:"die Beamtin",src:"the civil servant (female)"}]},{type:"match",pairs:[{trg:"die Schwangerschaft",src:"the pregnancy"},{trg:"der Einwohner",src:"the resident, the inhabitant (male)"},{trg:"das Lager",src:"the camp, the warehouse"},{trg:"die Botschaft",src:"the embassy, the message"},{trg:"ausschließen",src:"to exclude, to rule out"},{trg:"empfangen",src:"to receive (formal)"}]},{type:"match",pairs:[{trg:"integrieren",src:"to integrate"},{trg:"zugänglich",src:"accessible"},{trg:"abmachen",src:"to arrange, to agree on"},{trg:"einzahlen",src:"to deposit (money)"},{trg:"der Betrag",src:"the amount (of money)"},{trg:"die Bankleitzahl",src:"the bank routing number"}]},{type:"match",pairs:[{trg:"der Briefumschlag",src:"the envelope"},{trg:"der Briefträger",src:"the mail carrier (male)"},{trg:"der Onkel",src:"the uncle"},{trg:"ausführen",src:"to execute / to carry out"},{trg:"die Angehörige",src:"the relative, the family member"},{trg:"verwandt",src:"related (by family)"}]},{type:"match",pairs:[{trg:"der Käufer",src:"the buyer (male)"},{trg:"die Verkäuferin",src:"the sales clerk (female)"},{trg:"die Betriebsrätin",src:"the works council member (female)"},{trg:"der Bankomat",src:"the ATM (Austrian German)"},{trg:"die Brieftasche",src:"the wallet"}]}]}

]};

export default UNIT_19;
